-- Hard reset of public.testimonials to match the imported TripAdvisor
-- spreadsheet (Trip Advisor - Simple Reviews 1-150.xlsx). The previous
-- schema (author/source/source_date/headline/quote/avatar_url/wp_id) is
-- replaced with the columns from the export. testimonial_sets and
-- testimonial_set_items are kept — they're the category system the
-- testimonials block will read.

-- 1. Wipe all data (cascades to testimonial_set_items via FK on delete cascade).
truncate public.testimonials cascade;

-- 2. Drop legacy columns.
alter table public.testimonials
  drop column if exists author,
  drop column if exists source,
  drop column if exists source_date,
  drop column if exists headline,
  drop column if exists quote,
  drop column if exists avatar_url,
  drop column if exists wp_id;

-- 3. Add TripAdvisor-spreadsheet columns.
alter table public.testimonials
  add column if not exists review_number int,
  add column if not exists review_id     text,
  add column if not exists review_url    text,
  add column if not exists title         text,
  add column if not exists date_of_stay  text,
  add column if not exists trip_type     text,
  add column if not exists review_text   text;

-- 4. Constraints. review_id is the dedupe key for future imports.
create unique index if not exists testimonials_review_id_key     on public.testimonials(review_id);
create unique index if not exists testimonials_review_number_key on public.testimonials(review_number);

-- 5. Make review_text + review_id NOT NULL after adding them.
alter table public.testimonials
  alter column review_text set not null,
  alter column review_id   set not null;

-- 6. Insert 150 reviews from the spreadsheet.
insert into public.testimonials (
  review_number, review_id, review_url, title, rating, date_of_stay, trip_type, review_text
) values
  (1, 'r1052702616', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1052702616-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Simply Exceptional', 5, 'March 2026', 'Traveled solo', 'I just returned from the most incredible stay at Anamaya, and I can’t recommend it enough. From the moment I arrived, everything exceeded my expectations. The food was absolutely spectacular — and as someone with celiac disease, knowing that everything was completely gluten-free was a level of stress relief I never get to experience on vacation. Being able to fully relax and enjoy every meal without worry was such a gift. The staff at Anamaya truly make the experience unforgettable. Rueben and Gretel are wonderful, and their care and attention to detail do not go unnoticed. It happened to be my birthday while I was there, and they went out of their way to make it extra special. I felt so celebrated and cared for. Our retreat was led by Nikki Warren, and she was exceptional. Her ability to truly assess how we were feeling each day and tailor the yoga to our needs and abilities was such a gift. Every practice felt intentional, supportive, and exactly what we needed in that moment. And the spa services… I honestly couldn’t get enough. Do yourself a favor and spend some time with Diane — not only is she incredibly skilled, but she’s also just lovely to chat with. It made the experience that much more meaningful. What made the week even more special was our group. To Ashley, Diana, Emilie, Georg, Janet, Karen, Linda, Melanie, Nikki, Nora, Sophie, and Teddi — thank you for such a fun and unforgettable week! If you’re considering a wellness retreat, this is your sign. Anamaya is something truly special.'),
  (2, 'r1049995938', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1049995938-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Beautiful restorative week', 5, 'February 2026', 'Traveled as a couple', 'We had such a beautiful and restorative week at Anamaya. The food, accommodations, classes, staff, guests and overall energy was top notch. This is my second time doing a retreat at Anamaya so I had high expectations but everything still exceeded. We will be coming back again for sure. Highly recommend Anamaya to anyone looking for a week full of self care, beauty and restoration.'),
  (4, 'r1045214098', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1045214098-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Impressive Panoramic Ocean Views of Santa Teresa and Montezuma. Seamless Trip at Anamaya Resort', 5, 'December 2025', 'Traveled solo', 'I stayed at Anamaya in Montezuma, Costa Rica, and the overall experience was a dream from start to finish. Everything so tidy, the entire place is genuinely beautiful, well cared for, and thoughtfully put together. Green junglish, delicious. The rooms and common areas are spotless, comfortable, and surrounded by nature, with views of the jungle and ocean that make it easy to relax. The open-air design works well in the climate and adds to the calm, peaceful feel of the resort. The food is some of the best in Montezuma, hands down. Every meal was fresh, flavorful, and like nourishing, satisfying. It has vegan options but also theres meat options, the food makes everyone ask about the recipes, and they asked for my dietary needs and stayed like super strict about it. They have two huge shalas w ocean view, spa, cold plunge, pool (love that), and a sauna i mean cmon The yoga and movement classes were super advanced but like accessible, whether you’re experienced or not. The schedule felt balanced and never rushed, with plenty of time to rest, explore Montezuma waterfalls thorugh their entrance to the waterfall, theres a beach nearby too What stood out most to me was how smoothly everything ran. The staff were friendly, organized, and helpful, and I never had to think twice about logistics, transportation, or planning. It made the entire stay feel easy and stress-free. The staff booked everything for me, from the ferry to the hotels after the ytt Anamaya Resort has my heart really'),
  (5, 'r1041786160', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1041786160-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Zendasana', 5, 'December 2025', 'Traveled as a couple', 'I will forever be grateful for a superb 3 weeks stay at Anamaya during my yoga teacher training course. Anamaya is a true paradise and the staff is like family. The food which is anti inflammatory is so delicious and will make you feel totally rejuvenated. Can’t wait to come back again here and feel the zen!'),
  (6, 'r1037771711', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1037771711-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'A Chef travels to Aramaya', 5, 'October 2025', 'Traveled on business', 'Wow! 20 Great Guys & I went to where, Time has stood still for 7 days, beyond expectations, surrounded by beauty, the ocean, the rain forest. Enchanting. The owners and staff at Aramaya perfectly executed and timed life there. They are proud, exceptional operators. The food, fresh picked from their farm, fresh day boat fish, fruits, vegetables all carefully crafted by a competent team of kitchen warriors. We will return, Thank you All at Aramaya'),
  (7, 'r1037771363', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1037771363-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'WOW!!!', 5, 'November 2025', 'Traveled with friends', 'Absolutely spectacular in all aspects!! Definitley recommend!!! Such an amazing venue!!! I can’t say enough, you will be impressed!!!'),
  (8, 'r1037713085', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1037713085-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Pura Vida', 5, 'October 2025', 'Traveled with friends', 'What a fantastic experience. Couldn''t have been any better. Although we went during the rainy season it was amazing. Anamaya felt like home right away. Would definitely recommend to whoever wants to spend some time in paradise on earth.'),
  (9, 'r1002851758', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1002851758-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'A Sacred Path', 5, 'March 2025', 'Traveled solo', 'I spent two glorious weeks at Anamaya in late February thru March 8th. It was my third trip. Home now for over a month and the experience is deeply sealed in my heart. Anamaya is a sacred place that strengthens the mind and body. Over the course of a week''s retreat, Anamaya works its magic by providing healthy, delicious food, yoga, breath work, lovely rooms (with the best balconies overlooking the jungle) and artistic attention to detail throughout the resort - tropical flower arrangements, beautifully set tables for dinner etc. And Costa Rican coffee always ready at 6:00 am. The jewels are the yoga retreat leaders and Anamaya''s staff... a special shout out to my favorite massage therapist, Barbara!! She walks on water and your back!! I had the good fortune of participating in a Sacred Pathways: Sacred Medicine Retreat led by Joseph, Anamay''s owner and Chela. Joseph was attentive to every detail of the week, made certain every attendee''s needs were met and guided us through outstanding programming - including breath work that for me is life-changing. His kindness, compassion, generous spirit and dedication to Anamay''s mission was present every single moment. We all felt it. Chela provided beautiful ceremonies and allowed us to experience Costa Rican spirituality. The issues of the day quickly descend upon return home....and when they do, I close my eyes, breathe and picture myself on Anamaya''s yoga decks overlooking the Pacific Ocean. And peace returns... Anamaya''s spirit is alive... and remains with you. I hope my path always guides me back to Anamaya. It is Sacred Medicine.'),
  (10, 'r1002126669', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r1002126669-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'The most magical yoga experience!', 5, 'April 2025', 'Traveled solo', 'I am so grateful to have chosen Anamaya as the destination for my yoga retreat. Karen Love, yoga retreat leader, is a beautiful soul who inspired me in my yoga practice and through her workshops. The owners were friendly and kind. Every single plate of food was delicious and I never felt hungry. There’s wine and beer available to purchase. The brewery’s a 5min walk away and is a nice excursion if you do get hungry between lunch and dinner. Zip lining is also a fun excursion, only a 5min walk away. The surfing is 100% worth it, even if just for the beautiful hike to the sandy surfing beach. My room, lotus, was extremely comfortable and clean. I spent a lot of time on my balcony’s hammocks, enjoying the view and breeze. The bathroom and shower are indoors. The pool is gorgeous and a perfect temperature. The spa treatments were all incredible. If flying in to San Jose, the walk to the domestic terminal was an easy 5 min. If you have time to waste before the flight from/to Cóbano I suggest taking an uber to la calle street food or to the city mall. Cost was $5-$10 each way. Oh and go to Santa Theresa if you can while you are staying at Anamaya. A beautiful beachside town and the ocean is perfect to swim in. And sunset is beautiful.'),
  (12, 'r984556540', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r984556540-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'I could go back again and again!', 5, 'November 2024', 'Traveled solo', 'A perfect getaway for all, especially Solo travellers who want to enjoy the good things in life, rest, recover and make new friends. I left felling I got far more than what I payed for. Such an incredible experience and I am definitely want to return!!! I stayed in the Anahata room and Lotus Cabina which both have wonderful views. I also visited some of the other rooms and all were extremely beautiful. You just have to choose what matches your preference. However if you''re a light sleeper, I would recommend staying away from the Anahata room as it is in the main house. I sleep deeply so it didn''t bother me but if other guests are up early or go to be late, you can hear the noise. Otherwise if you want ease and convenience, Anahata room is right by many of the resort features. The Lotus Cabina was my favourite of the two, for the cosy feel and the deck. The yoga is great, you can have a look at the website to see what style/intention suits before you book. The spa treatments are a must! Don''t leave without having one. If you like a deeper massage, I recommend the Ashiatsu massage. It''s intense but so freeing! The pool is lovely and there are a few floatys to support weaker swimmers which is a lovely addition. There is also an infrared sauna and ice bath which are super for the rainy days if you''re there in the rainy season. The FOOD IS AMAZING! You will feel nourished and fulfilled with the incredible, hearty, great meals they provide. They hit the jack pot on flavour and satisfaction every time. For the excursions, I can definitely recommend the Zip-line tour as an exciting way to see the jungle from a different perspective. Also, plan to skip one meal to go for lunch or dinner at the Butterfly Brewing Co & Imago Gastro. They also do amazing snacks and cocktails (spicy passion fruit margarita... Fantastic!) if you can''t bring yourself to skip one of the amazing Anamaya meals. You don''t know what you''re missing yet but once you go you''ll be so glad you did!'),
  (13, 'r968925006', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r968925006-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Best retreat center in Costa Rica!!!', 5, 'September 2024', 'Traveled with friends', 'This is one of the most magical places on the planet. The views are second to none with a 270 degree panoramic look at miles of jungle and ocean. The food is healthy, fresh and almost all of it comes from their permaculture farm. Lastly, the staff is so personable that they will instantly welcome you as their family. Definitely join a retreat of just come visit.'),
  (14, 'r963482111', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r963482111-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Beautiful in many ways', 5, 'July 2024', 'Traveled as a couple', 'This trip really exceeded all expectations. The place is as beautiful as the pictures would suggest! The yoga teacher (Cristiane) was awesome, and provided options for all levels. Nearby activities (zipline, beach, surfing, etc.) fun and easy to get to. The food was delicious, and the kitchen asked each of us our preferences and provided accordingly. Well worth the extra small plane ride to get there. I''d love to come back and spend another week soon!'),
  (15, 'r929297073', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r929297073-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anamaya is such a blessing', 5, 'November 2023', 'Traveled with friends', 'Anamaya is such a spectacular experience!! I went with a friend for a yoga & wellness retreat. Our yoga instructor Carrie Ingham was incredible! Our entire group bonded beautifully throughout our week & practice. The food, the location, the daily morning Yoga, evening restorative yoga, meditation & acro yoga workshops & spa treatments helped my mind, body & heart be restored & heal. Anamaya is a true blessing & I pray to return to Anamaya for such an experience like this one again.'),
  (16, 'r913970228', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r913970228-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Pure magic', 5, 'August 2023', 'Traveled solo', 'This place is hands down one of the most amazing and magical places on Earth. I traveled solo and stayed in the Gaia house and my week couldn’t have been more perfect. I felt 100% safe and cared for the entire time by the wonderful people who are the staff here. The views are absolutely incredible. Looking up during yoga to see the jungle and the ocean was a moving experience in itself. My heart will be longing for that yoga deck for the rest of my days. The food is delicious, the people rock, the spa is excellent, and the pool is stuff out of dreams. There’s wildlife and animals everywhere. You will without a doubt see monkeys, maybe even whales if you come at the right time. If you’re considering booking a trip here, just do it. Stop thinking about it and book now. You won’t regret it and you will fall in love with this place like everyone else who comes and spends a week in the magic. This place has truly changed my outlook on life and helped me find myself again.'),
  (17, 'r913942781', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r913942781-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Awesome Yoga Retreat', 5, 'August 2023', 'Traveled solo', 'I have always wanted to go to Costa Rica. I went online to find a yoga retreat and Anamaya had good reviews. I knew the landscapes would be beautiful, but the whole experience exceeded my expectations in so many ways. First of all, the location is stunning. Overlooking the ocean, with a disappearing pool, open air living room, common dining room with fresh flowers on every table. The yoga retreat leader, Jess, did much more than yoga. She led meditation and relaxation while watching flickering candle lights, She also presented workshops, creativity sessions, letting go ceremony, and session on how to nourish our bodies. Her voice was so soothing and relaxing. And her enthusiasm inspired all of us. She was just a joy. We dined on healthy, delicious and pretty food, three times a day. There was eleven in our group. We really had great conversation over all the meals. In our downtime, we hung out in the common living room overlooking the blue/green ocean, playing our favorite songs and dancing to them. Or playing games and just sharing and laughing. Anamaya offered excursions and activities. I did a bioluminescence boat ride. It was at sunset and we all dove off the boat, waived our arms around and it looked like shooting stars in every direction. And last but not least, all the staff was great. They were friendly, gracious and responded to every request. I''m going back next year. It ranks in the top vacations of my life and I''ve been to Italy, Kenya, Mexico and other countries. It is all the above things, combined together that made this a special week. Kelly Scheufler'),
  (18, 'r899578040', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r899578040-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Special location and beautiful people', 5, 'July 2023', 'Traveled on business', 'This is the most beautiful, most unique and most special place. Tambor airport is small, the drive is not too far and the staff are so welcoming. Joseph and all staff were universally kind and understanding of all challenges and totally fluent in English.'),
  (19, 'r893153108', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r893153108-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anamaya is the best and most beautiful place to rejuvenate', 5, 'February 2023', 'Traveled solo', 'The most amazing week. I cannot recommend Anamaya enough. I went as a solo traveler and had the best time. The group ranged from late 20s-early 40s plus a couple in their 60s. Everyone was so kind and welcoming. It felt very easy to show up alone. The Anamaya staff was awesome. They take such good care of the guests. They arrange any off property excursions for you, so you never have to lift a finger. The food was incredible. I was blown away by how delicious, fresh, healthy and clean it all was. Normally after a week of traveling I’m ready to be done eating “out” but this food never made me feel gross or unhealthy. Fresh coconut milk in my coffee every morning was a highlight. I stayed in a single person room which was lovely. Very clean, AC, private bathroom, quiet and a view of the ocean. The yoga instructor, Meg Shuba, was phenomenal. There were classes twice a day and everyone could choose how often they wanted to attend. The whole week was a great balance of group activities plus time for solo adventures. Montezuma is beautiful. This trip was the perfect was to disconnect, relax and rejuvenate.'),
  (20, 'r885666253', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r885666253-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Perfect!', 5, 'March 2023', 'Traveled solo', 'Anamaya is amazing retreat up on a mountain overlooking the ocean. The Anamaya experience has it all ~ breathtaking views, outstanding staff, delicious food, and beautiful well planned accommodation. It is the perfect place to practice yoga, take part in excursions or simply relax. Even though you were deep in the jungle, everything is incredibly clean. Every single staff member was exceptional. The body work offered is incredible, and definitely world class. I will return!'),
  (21, 'r880111510', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r880111510-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Absolutely perfect week at Anamaya', 5, 'January 2023', 'Traveled solo', 'This was my 2nd time to Montezuma but my 1st solo trip. I was needing an adventure and some time to rest after a rough few months. Anamaya exactly as pictured - gorgeous views, delicious food, lovely staff. I spent most of my week by the pool or on my deck, looking over the ocean at whales in the distance, and hummingbirds in the trees. I stayed in the loft of Gaia House with 3 other women - it was perfect for a solo traveller. The other travellers I met were very friendly and I loved getting together in the evenings for dinner to recap everyone''s day. There was no pressure to do anything - everyone had their own reasons for being there. I would go back in a heartbeat and I miss it dearly.'),
  (22, 'r876934781', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r876934781-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'The Heart of Anamaya Still Beats', 5, 'October 2022', 'Traveled solo', 'I have been to Anamaya several times throughout the years. I never like to stay in the same places but I come back because of the staff, the amazing food, the cost effectiveness, and most importantly, the view! The view from the yoga decks is still one of the best in the world. You never get bored of it. I noticed that there was a few bad reviews on Anamaya, as noted in my previous review, the 5 star experience is not for the luxury but all of the above that I have mentioned. Yes, due to Covid, Anamaya had to make some changes to survive. I even noticed the last time I came during low season they opened up the classes to outside guests during low season. Post Covid, sometimes there are two groups at Anamaya ( yoga retreat and a yoga teacher training), and their activities are now a La carte. I don’t think this is a bad thing because the last time I came, there were packages such as yoga and massages, but what I found was that sometimes you didn’t feel like doing yoga but were obligated or you didn’t like the package offerings. Paying for activities individually ensures you only pay for what you want. I found it quite funny that there were several reviews complaining about cliques when the 3 reviews were very similar complaining about those people. Depending on the retreat leader you may get a different crowd, do your research. If you happen to join a yoga retreat and there’s a YTT group at the same time, know that they’re going through a lot and they are very busy, but a smile and a hello is always returned. The reviews also complained about cracks in the stone. What they didn’t tell you is that they took a photo of an outdoor bathroom that is opened to the elements. Yes, there are cracks as nothing is perfect but Anamaya is still very clean and well maintained. It’s a very tropical place so things wear and tear much faster. It’s like this in most of the places I stayed in Costa Rica (and any other tropical climate). This time I stayed in dharma room. It’s at the bottom of the hill so it’s a bit of a trek up to the main house but convenient for the lower deck. Note that at night, you can hear the critters running around the yoga deck. I also noticed that there’s now a vacation house lower down the hill and depending on who is there, they may play loud music that you can clearly hear (okay in the room but annoying when you’re on the hammock). The wifi is really poor in this room so if this is a deal breaker you may want to get another room (although when I first came to Anamaya there was no wifi in the rooms!) The heart of Anamaya, which comes from the staff is still there. Yes, there are changes and yes, things are tired but if you walk out on the yoga deck and you are unhappy, that’s on you.'),
  (23, 'r876877493', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r876877493-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anamaya is truly Magical!', 5, 'January 2023', 'Traveled with friends', 'The experience at Anamaya was truly magical! From the beautiful location in the jungle overlooking the ocean, to the helpful and kind staff, everything was perfect. I went for a week long yoga retreat and I couldn''t have asked for a better location to practice yoga 2 times a day. The food was healthy and plentiful everyday which made my body feel great. The infinity pool was wonderful to cool off in when it got too hot. The Bali room was perfect- from the air conditioning to the outdoor shower to the hammock overlooking Montezuma. I highly recommend Anamaya to anyone who wants to practice yoga in paradise!'),
  (24, 'r876187837', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r876187837-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'The MOST breathtaking escape! MUST VISIT!', 5, 'February 2022', NULL, 'I don''t even know how to begin... From pulling up on the property to a view so breathtaking it brought tears to my eyes to the beauty of the property at every corner... Anamaya is truly a slice of heaven on earth. Not only was the yoga beautiful and catered to each person''s skill level, but I had so many amazing conversations with the new friends I met there as a solo traveler. The staff were beyond courteous and so helpful and friendly, the food was incredible (I am going back just for the fresh fruit after your morning yoga flow) and taking an outdoor shower with a view of the ocean and monkeys swinging from the trees was an experience I will never forget. If you need an escape, an amazing vacation, a yoga retreat or time to know yourself a little better look no further.'),
  (28, 'r854366168', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r854366168-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Beautiful Resort run by Beautiful & Dedicated Team', 5, 'August 2022', 'Traveled with friends', 'Just returned from my 1st ever yoga retreat, and 2nd visit to CR. CR was already one of my favorite vacation memories - the team at Anamaya managed to top my expectations. They are kind, hardworking, and caring individuals that go above and beyond to ensure you are comfortable and well cared for during your stay. We had a large group with some difficult medical issues for one of our group members. The team at Anamaya showed amazing care, compassion, and no-judgement - allowing her to fully engage in events and classes despite difficulties. The yoga was top-notch, and the food was a delight at every snack and meal. There is a small gift shop that includes wine that you can purchase for dinners, and reception organizes a number of excursions to ensure your getting the best local life has to offer. Our trip turned out a little different then expected, but the Anamaya staff made sure each individual person had the best experience possible.'),
  (29, 'r839076242', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r839076242-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Worth the wait', 5, 'April 2022', 'Traveled solo', 'Absolutely beautiful setting, delicious meals and a week that left me feeling refreshed like I had been been away for a month (in all the best ways). A trip to Anamaya had been on my bucket list for a number of years and it did not disappoint. You can do as much or as little as you want and the staff are so supportive to help with anything you could possibly have questions about. The spa services… I dare you to try only one…. Luxurious … if you are looking for a refresh this is a great place to go'),
  (30, 'r838485929', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r838485929-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Peace in the jungle', 5, 'May 2022', 'Traveled solo', 'Beautiful facility in the jungle, YOU ARE in the JUNGLE. Most people will need to take 2-3 planes to get there—-sounds complicated? Their team are experts at making this easy—and take all the stress away. Everyone in my yoga retreat were solo travelers, so that was nice. Our Yoga host Eva was the best and she was with us throughout the stay which was nice to be immersed in her wonder. I slept like a champ the entire stay. Nice AC in all rooms. I enjoyed an open shower which was great. The facility is tremendously kept by staff. I enjoyed 3 massages in my one week! Their team is that good! Barbara gave me the best Ashiastsu ever, I saw her twice ! Gretl and Al were top notch in customer service. Amazing how they remember everyone’s name.'),
  (31, 'r837384116', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r837384116-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Stunningly beautiful and restorative', 5, 'April 2022', NULL, 'I can''t say enough positive words to describe my stay at Anamaya. The place itself is gloriously beautiful. The staff is caring, warm, attentive and kind. The food was delicious, creative, healthy and satisfying. The spa services are remarkable. The two yoga decks are so beautiful. There are many fun day trips to choose from. Following your spiritual yoga experience on the open air deck, picture yourself in a blue tiled pool up in the jungle listening to monkeys and birds and looking down over the ocean, surrounded by lush greenery and colorful flowers. Or relaxing quietly in your hammock reading a book and surrounded by nature. It doesn''t get much better than that! I am a restored, balanced person since this trip and truly hope to return one day.'),
  (32, 'r837129913', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r837129913-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Yoga Retreat', 5, 'April 2022', 'Traveled solo', 'The experience was great! Natasja energy and knowledge is execent and you can feel it in Your spirit. Anamaya is a beautiful place and the service and warn of the people made me feel right at "HOME"🙌🙌'),
  (33, 'r836786758', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r836786758-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Yoga retreat', 5, 'April 2022', 'Traveled with friends', 'Beautiful setting, amazing instructor, awesome food. Instructor was knowledgeable, friendly and very helpful. Retreat staffs are professional and friendly. They all went above and beyond to make sure we felt welcome and at home.'),
  (34, 'r832963809', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r832963809-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Best way to Re-treat and Revitalize yourself!', 5, 'February 2022', NULL, 'I live in Canada and winter months are very harsh at every level so coming to Anamaya''s retreat was the best way to refresh and revitalize myself! Loved Natalia Chaverri''s retreat week, her yoga/workshop classes were fantastic! she was very welcoming, knowledgeable and a beautiful soul to be around :) The place is beyond beautiful, with top notch healthy food, friendly staff and gorgeous ocean views and of course ,,,Anamaya has the best infinity pool in town! ....can''t wait to book my next retreat again and enjoy this magical tropical place with the most stunning sunrises! Thank you Anamaya! :)'),
  (35, 'r823340345', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r823340345-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'a week to heal and recharge', 5, 'December 2021', NULL, 'Everything was amazing in Anamaya, from the location, the staff, the food, well everything. Lola Rephann was amazing, he taught us many things and even for folks that we are not Yoga experts, more like new to Yoga, he never made us feel out of place. The frequency of all the people that went to the retreat made the week even better, so quiet, so respectful, its certainly one place you don''t go to party, but party within yourself, to find that silence we crave in a hectic world. I will be saving again to go , wouldn''t be surprise if I end up going once every year!! Totally worth the time going in . That is probably the only caveat, ITS FAR! hahaha, but most good things are.'),
  (36, 'r822571095', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r822571095-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Magic Place', 5, 'November 2021', NULL, 'Anamaya is a magic place. The energy of the place, the food, the scenery, the people... all combined made it an unforgettable experience. Would definitely recommend as a yoga retreat or just to unplug and relax from the outside world. Absolutely loved my vacation. Great for solo travelers.'),
  (37, 'r822092353', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r822092353-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Pura Vida Bliss', 5, 'November 2021', NULL, 'I don''t have the capacity to put into words the welcoming and loving nature of this beautiful retreat <3 Very loving and high regards for the anamya family I participated in the Tantra retreat with Jivana. Whom i very much am honored to have met.'),
  (38, 'r821953197', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r821953197-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing retreat', 5, 'November 2021', NULL, 'I came accross Anamaya by chance. I was on my way back from the Montezuma Waterfall. I was thinking of going to a yoga retreat and Anamaya presented itself to me 😊 I had an amazing time, great yoga sessions, met wonderful people. The food is healthy and delicious. The view is exquisite. Probably one of the best places to do a yoga retreat.'),
  (39, 'r821921351', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r821921351-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Heaven in Montezuma', 5, 'December 2021', NULL, 'The most serene environment, amazing staff, wonderful rooms. Everything is perfect. I love the food that is provided. I had fun seeing monkey families all of the property. The care and attention the staff put into the grounds shows.'),
  (40, 'r819114970', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r819114970-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'YTT in Paradise', 5, 'October 2021', NULL, 'I did my YTT at the Anamaya Resort and I could literally not think of a better place to do a YTT. Everything was exceptionally amazing. The staff was very helpful and very friendly. At one point it almost felt like we were a big family. The food was splendid! Provided fresh food from their own farm and great vegan/vegetarian or any dietary request options!!! The rooms are very beautifully designed. I stayed at the Casita dorm and could not have had a better experience. The dorm is equipped with two showers one of which is an outside shower... what an amazing experience! even taking a shower was an adventure!! Generally the whole resort is nestled in the beautiful jungle overlooking the ocean and cliffs of Montezuma. The Yoga Shalas are amazing! During our practice we saw so many wildlife creatures and monkeys jumped on the roof joining our practice. There is also a massage service available and the treatment options are insane! Lots of different massage styles are available. I can only recommend this place from the bottom of my heart, is it for a retreat, just vacationing or especially if you want to do your YTT!!!!'),
  (41, 'r815025173', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r815025173-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'What a magical experience', 5, 'October 2021', 'Traveled solo', 'Annamaya was exactly what I was hoping for and so much more. The photos truly do not do it justice. The beauty of the resort has to be seen to be believed. I stayed in the jungle cabana and woke up to the beauty of the jungle every morning. The staff is incredible, super friendly and helpful. But Christiane was absolutely the host with the most. She made our retreat group feel comfortable to immediately and facilitated a fantastic time for us. Our group made fast friends and many of us said it felt like being at camp. Thank you so much to all the Annamaya staff! I can’t wait to return and bring more people to your wonderful resort!'),
  (42, 'r806869521', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r806869521-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Life changing experience', 5, 'August 2021', 'Traveled as a couple', 'What an amazing place to stay, especially if you want to work on yourself, or come back to mother earth to find you center. Property is hidden up the hills of Montezuma and absolutely beautiful. Everyone from owner to all the staff is very kind and accommodating. Where to begin to explain this magical place, From all the beautiful trees, jungle and landscape to infinity pool looking at the ocean. With amazing food from our wonderful chef Jeff and so much to offer this is a true oasis. Yoga Retreat for beginners or advanced yogis is amazing, mostly to our yoga teacher Lola who through yoga , with her wisdom and experience made some great life changing transformations for most of us. She was our teacher and our friend, our guide and our listener, just to name a few. Its definitely an experience that should not be missed to say the least.'),
  (43, 'r801808647', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r801808647-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'An amazing place to heal', 5, 'July 2021', 'Traveled as a couple', 'It’s hard to put into words how special this place is. The Staff made you feel like family, the food nourishes your body, the view and the yoga are amazing. I highly recommend getting a massage by Marta. I felt like a different person when I Got off her table. Seriously, I had a healing experience in a very deep level. After the long year and a half of Covid and being a business owner, I can’t think of a better place to heal, relax, and rejuvenate. I look forward to joining Kim and Scott Goyette next July. I plan to make this an annual thing! Oh, and the city of Montezuma is small and charming and the beaches are fantastic'),
  (44, 'r799782636', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r799782636-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Week long yoga retreat with Jackie Chiodo', 5, 'June 2021', NULL, 'Anamaya is a magical place in the middle of the Jungle! The staff goes above and beyond to make you feel comfortable and spoiled. I was traveling solo and decided to be in the group room with some other ladies - that was a great decision. The food was amazing, creative, delicious and healthy. Jackie Chiodo who lead the yoga retreat is a pretty amazing instructor. She made all levels of yogis feel good. Her teachings and outlook on life is hopefully forever imprinted in my mind. It was such a moving experience to be in this location, practicing yoga I''m trying to figure out how I can return next year.'),
  (45, 'r797857514', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r797857514-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'BEST EXPERIENCE EVER!!!', 5, 'July 2021', 'Traveled as a couple', 'My fiancé and I just returned from two weeks at Anamaya, and we can say without a doubt it was the best decision we’ve made in a long time. I’m a big fan of retreat-vacations, and have been to a fair amount all over the world. Anamaya is the best I’ve experienced! After this last year we felt spiritually depleted, and wanted to do something healthy to lift our souls. This was the best thing we could’ve done- the people, the place, the amazing workshops, yoga, surfing, diving, food, and new friends we’ve met, not to mention the gorgeous facilities. It really couldn’t have been better. The staff in particular- Laura, Alberto, Ruben, Gretal, and so many more including all the amazing folks who so diligently cleaned our rooms every day, gardened, cooked the most amazing meals, to the insanely talented massage therapists and of course- the best yoga teacher of all time!! (If you’re lucky enough to attend a retreat here book it with Zarelly! She is actual magic!). They made us feel like family, and are such beautiful and kind souls. We feel grateful to have gotten to meet each and every one of them. I saw there was a poor review someone had posted during the pandemic, and I have to say I was shocked to read it because it didn’t reflect my experience here at all. This year has been crazy, and businesses (and people) have done what they needed to survive. As a person who is privileged enough to still be employed and vaccinated, I felt so good about bringing my business to Anamaya, and in return am leaving with a full heart and renewed hope moving forward in life. I’d highly recommend anyone else in need of a reset come visit!! You won’t regret it.'),
  (46, 'r797405924', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r797405924-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anamaya is a dream. They took care of the essentials and gave me the time and space I needed.', 5, 'July 2021', NULL, 'We did the yoga retreat at Anamaya and I couldn''t think of a more perfect experience. First, the staff was sound kind and genuine that I left feeling like an extended family member. You really feel nurtured during your stay. Along with Yoga twice a day, I also took surfing classes, the cacao ceremony, osha meditation, a cooking demo, had a deep tissue massage, and toured their farm. It was all amazing and I loved every bit.'),
  (48, 'r774761710', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r774761710-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'A Highlight Of My Life', 5, 'February 2020', NULL, 'The beauty, sounds , smells, tastes, and inner peace I experienced during our week there have sustained me through these crazy times of COVID. The service and commitment to excellence was the icing on the cake to the resort itself. Every morning, waking up to the sounds of the jungle, the incredible sunrises, the joy and bliss of it all....caused endorphin rushes of pure gratitude. The kinds of people that do a retreat such as this were truly amazing as well. Lovely people from all over the world. As we went through our week, we grew closer as friends. We got to tour see each cabin close up. Whichever you choose , you will feel like this is the happiest place on earth. If you leave the resort at all, make sure you swim in the waterfall. We waited til our last day...Do not miss this experience. The peaceful yoga every morning and evening perfected this experience. If you are reading this, you must go one day :)'),
  (49, 'r761539506', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r761539506-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Such a delicious lunch menu and unbeatable view!', 5, 'July 2020', NULL, 'My boyfriend and I were staying a a property nearby and lucky for us, Anamaya was open for non-guests to dine at (a Covid-19 accommodation). We ate there every day we were in Montezuma. As a vegan, I was able to order a different meal each day, which doesn''t happen super often. Not only the food was delicious, but the service was consistent and the ocean view was the best I''ve experiences in Costa Rica!'),
  (50, 'r751945154', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r751945154-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anamaya Yoga Retreat', 5, 'March 2020', NULL, 'My stay and Anamaya Resort was excellent. The resort was beautiful, and the staff and food were amazing. My jungle cabina was perfect, I loved being surrounded by lush vegitation and wildlife. The yoga, activities, and spa treatments were also amazing. I have nothing but great things to say about Anamaya, and I will definitely be going back.'),
  (51, 'r751230341', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r751230341-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Magical', 5, 'March 2020', NULL, 'This was such a special experience. It far exceeded my expectataions. The yoga guides Kelly and Ted exude love and passion throughout their every contribution and then some. The treatments, Lomi Lomi four hands and Ashiatsu massage, are the best I''ve ever experienced. Don''t miss the cacao ceremony and chakra workshops! And sunset at the beach was very special. Can''t wait to visit Anamaya again! Pura Vida.'),
  (52, 'r749920889', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r749920889-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Still feeling the pura vida long after this vacation', 5, 'February 2020', NULL, 'My stay at Anamaya was an incredible experience. The venue, the food, the staff, the instructors, and the community it attracts- wow. The setting itself is beautiful- overlooking the ocean. The infinity saltwater pool is very peaceful. The staff was lovely and very helpful with any questions. The food was fresh and incredible. I looked forward to every meal (and snack) in the schedule. The teachers were so supportive and skilled at building community. It was such a pleasure to spend a week with wonderful humans, looking for a little rejuvenation. No shortage of things to do or see in the area, either! I left feeling both rejuvenated and energized in mind, body, and spirit. I would definitely go back!'),
  (53, 'r749552027', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r749552027-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Incredible Experience', 5, 'February 2020', NULL, 'This trip exceeded my expectations. The yoga was awesome, the hiking was a perfect way to start every day, the surfing was so much fun, and the food was delicious and healthy. It was hard to leave this beautiful place.'),
  (54, 'r749225610', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r749225610-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Will leave you feeling fantastic!', 5, 'February 2020', 'Traveled with friends', 'Not sure whether it was the beautiful surroundings, yoga twice-daily, the gourmet gluten free meals direct from the farm, or the wonderful staff and friends - but I felt better than I have in many years. What an amazing experience. I would definitely go back!'),
  (55, 'r747661276', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r747661276-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing experience', 5, 'February 2020', NULL, 'I heard about Anamaya from a friend who had recently spent a week there for a yoga retreat. It sounded like exactly what I needed so I reached out to sign up. There wasn''t any accommodation available so I had my name added to a waitlist. Checked back in with them a week later and they moved some stuff around to make it happen - which I really appreciated. My time at Anamaya was magical. Lucy Hamel, the yoga instructor, was absolutely fantastic!! She made every one of the participants totally comfortable and catered to individual needs while keeping the sessions going. During the week, I was pleasantly surprised to find that my yoga practice progressed nicely under Lucy''s guidance. There were a ton of optional activities and that kept most of us busy. The highlights were the farm tour and the beach trip. The things that really stood out were the amazing people - all the participants as well as the fantastic staff of Anamaya. They are such a wonderful and caring team, and they go out of their way to make everyone comfortable. The food was outstanding and Chef Jeff is a whiz! He created a variety of unique, well-balanced meals that had us eating really clean, healthy and tasty food! I wish I could have that food all the time!! And for those of us who wanted some down time and pampering, the spa treatments were so relaxing! Each of the massage therapists were awesome! I had such an amazing time and felt totally rejuvenated. Would highly recommend Anamaya to anyone who wants to have a great experience unplugged from everything.'),
  (56, 'r746765443', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r746765443-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Gorgeous location, stunning views from the two yoga decks', 5, 'February 2020', 'Traveled solo', 'Anamaya is amazing. The property is very beautiful. Staff is very friendly, well organized and helpful. It’s everywhere very clean. The rooms are wonderful and the view from the two yoga decks is amazing. The yoga teacher was excellent. You can do several other activities or just hanging out at the pool or at the nice beaches in Montezuma. They offer 3 times a day meals with organic food which was really good. I enjoyed my stay very much but it would be great if more than 10 Yoga classes would be offered a week (e.g Friday night/Saturday morning).'),
  (57, 'r746603334', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r746603334-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'paradise by the moon and sunlight', 5, 'January 2020', NULL, 'this is a magical place. It is hard to put into words what your experience here is... the people, the plants, the yoga decks, the birds, the ocean, the butterflies, the yogis, the bugs, the food, did I mention the food, the local town, the waves, ....magic and life changing.'),
  (58, 'r742386445', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r742386445-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing trip', 5, 'December 2019', 'Traveled solo', 'I visited Anamaya for a special “New Years retreat” at the end of Dec/start of January and had an incredible time. The other guests and the staff were truly what made it an exceptional experience including our teacher (Lena) for the week. I was traveling solo as were at least 60% of the rest of the group, but it seemed a good fit for solo travel, couples and families with adult kids. Every activity was optional but you could always find someone up for what you wanted to do - I did all the yoga classes, the beach and farm tour day, two spa services and horseback riding on the beach with a small group. The rest of the time was simply spent relaxing by the pool, hanging out with other trip-mates and exploring the nearby town. The staff was incredibly accommodating with food restrictions for others, and I didn’t expect it (all gluten free/dairy free, mostly vegan) to be so delicious. The minor issue of noise from a nearby bar/club on the last night was addressed by the staff the next day - my beautiful room (Gaia) is one of the newest and the staff may not have anticipated that more noise prevention was needed. Overall an exceptional trip that I would recommend to anyone from yoga newbies to experienced practitioners.'),
  (59, 'r742299854', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r742299854-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'A Magical Retreat', 5, 'January 2020', NULL, 'Anamaya in person was even more beautiful then the pictures! The staff is amazing, friendly and very helpful. The food was incredible - so fresh and tasty and they cater to dietary restrictions. We were able to visit the farm where most of the food came from, Rancho Delicioso. We did a workshop and yoga with Crisitane and she was wonderful. She is positive, passionate and creative in all she does. She really made us feel comfortable - we truly enjoyed our time with her. I can''t wait for my next trip to Anamaya!! Thank you for a restful, fun and amazing week!'),
  (60, 'r742209139', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r742209139-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing! Best vacation and Experience of my life!', 5, 'January 2020', NULL, 'My week at and Anamaya is almost indescribable! Upon arrival, the staff was smiling, warm, and extremely friendly in helping us get settled. We had the most amazing and absolutely delicious meals from Rancho Deliscioso with vegan options, and all sustainably produced at their farm. They staff was also very astute in helping prepare meals for us that have dietary restrictions . The best homemade coconut and oat milks I’ve ever tasted! Cristiane was absolutely amazing! You felt all the time, energy, compassion, love, and creativity that she put forth in preparing for all of our yoga activities. We also learned a great deal about infinite possibilities and how our mindset can create the future that we really want! I am sincerely changed by this experience and look forward to many more retreats at Anamaya In the future. I would definitely recommend this to anyone who wants to go deep inside and change their lives! The staff was so supportive of all of us during our entire week!'),
  (61, 'r742108824', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r742108824-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Quiet, Tranquil, Transformational!', 5, 'January 2020', NULL, 'I stayed in Garuda''s nest with 2 friends. 40 stairs up, but what a view! Just wish I could have seen a little more of the water, but being surrounded by a garden of fresh veggies that they use to cook the meals was pretty cool itself. Wifi was spotty at times, but I wanted to disconnect so it wasn''t a big deal. There were a plethora of activities to do! Horseback Riding, Zip lining, cooking class, salsa lesson, spanish lesson, 2 yoga classes per day, Watsu, Reiki, massage, facial, manicure, pedicure! Colynn was the yoga instructor for this retreat - what a fantastic teacher. She went out of her way to offer free meditations in the morning prior to yoga class - what a blessing! Food here is gluten free/dairy free, they are very aware and cautious of food allergies and made sure all foods are separate for those who need it. Overall, Anamaya was just a perfect week of Heaven and I will definitely come back. I would recommend my friends and my family for rest, relaxation, and rejuvenation.'),
  (62, 'r742097704', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r742097704-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Exactly the way it is advertised', 5, 'January 2020', NULL, 'Rarely do websites and reviews and photos live up to what I experience places - but Anamaya was a rare exception. I had a wonderful, restful retreat, with some amazing human beings - both on the staff and as guests. Colynn Vosburgh, our yoga instructor, was somehow perfect for what I needed and the yin fusion yoga, meditations, and workshops we had available to us ensuring we were able to work physically, emotionally, and mentally on centering ourselves. I stayed in Gaia house with four women I''d never met, but the norms and surroundings of Anamaya made us friends by the end. I can''t recommend this place enough. And the food? Out of this world!'),
  (63, 'r738576470', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r738576470-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing service and hospitality', 5, 'January 2020', 'Traveled on business', 'Sunil Inderjit and Chandran Mehta was one of the best servers I’ve had in hotels. Always ready to help out with my meal orders and even took the time to explain some of the interesting work practices they have such as sustainable sourcing of their plates from less fortunate towns and giving opportunities for people to work who may be otherwise unable to find proper employment. It’s always a pleasure to visit here.'),
  (65, 'r737996106', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r737996106-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Fantastic yoga Retreat at Anamaya Resort', 5, 'December 2019', 'Traveled solo', 'If there were more stars I would have give them! Abbé Ciulla Is an amazing person and great Yoga teacher. She really cares about you and makes her yoga classes a life changing event. Already looking forward to next year, will definitely join her retreat again.'),
  (66, 'r737908094', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r737908094-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anamaya was a magical and transformative experience', 5, 'December 2019', NULL, 'I had no idea when I stepped onto the gorgeous grounds at Anamaya that I would walk away from this experience feeling transformed and like there was a shift in me mentally and physically. The place itself it absolutely 5 stars, the food was unbelievable and the staff was outstanding. I felt 100% safe without any outside visitors allowed on site. The yoga teachers they draw are world class and the community of friends you make there is really something I didn''t expect but was a big part of the experience. I will be back!'),
  (67, 'r736316969', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r736316969-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Heavenly setting, great yoga classes, delicious food', 5, 'December 2019', NULL, 'I came for the yoga experience, thought the classes were great and the food healthy and inspired. Would l=not stay in the Jungle room again as there is no ocean view. The walk to the waterfall is easy and lovely. The cool water in the pools is a delight'),
  (68, 'r733644661', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r733644661-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Heaven on Earth! Life-Changing.', 5, 'July 2019', NULL, 'I''ve been meaning to write this review for some time, but have struggled with how to put my experience into words. I stayed at Anamaya for a week-long yoga retreat (with instructor Lola Rephann) in July 2019. This was a completely new experience for me and I wasn''t sure what to expect. I wasn''t sure about what the schedule would be like, the food and drink, down time, the other retreat goers, which room to pick, and also the travel to Montezuma from San Jose. All I can say is that everything came together in such an extraordinary way that it changed my life. The minute I stepped out of the taxi and walked onto the grounds, I felt at peace. The sheer beauty and aura of the resort is worth the trip. So, those things I was concerned about? The Schedule: Do what you want. Feel like doing yoga in the morning, please join. Want to sleep in? Do that! In fact, do as much or as little as you want. There is no pressure to participate in activities. There are some group activities, that as part of a yoga retreat, they encourage you to join, but no one is going to make you do anything you don''t want to do. The Food and Drink: I was a little apprehensive about a gluten-free, sugar-free, dairy-free, and mostly meat-free menu. I love sugar, hamburgers, and margaritas. I wasn''t sure if that would be for me. Also, I hate most things super healthy: celery, kale, turnips, radishes, onions, to name a few. And while there were those things in the food, I didn''t mind! If I didn''t like an ingredient I either didn''t notice or just didn''t eat it. The chef prepares a new meal every breakfast, lunch, and dinner. I never felt hungry, and the food was downright delicious! You just have to give it a chance. Seriously, the food was one of my biggest concerns, but I came to Anamaya to improve my life (mentally and physically) and I''m so glad I did. Also, if you want, there are a bunch of restaurants in town, you can hop a cab or hike any time for a cheeseburger or pizza. There is also a market in town where you can buy snacks and beverages. Anamaya provides guests with a kitchen and refrigerator for their own use. Drinks: The resort sells organic wine and I believe they have some spirits upon request. I bought a bottle of Malibu at Duty-Free to add to my smoothie on days that I was lounging. You can also buy wine and spirits at the grocery in town. I enjoyed after dinner conversations on the deck with wine. Other guests: As a solo traveler I was a little worried about the other retreat goers. Let me just say that by the end of the first day I felt like I had known these people my entire life. Our group was one big family. You could hang out with the group, or go off and nap in your hammock solo. No judgement, no vanity, just peace. Before I arrived, I figured I''d be spending most of my downtime by myself reading a book. That was not the case. There was always someone down to go hiking, swimming, surfing, horseback riding, or hang by the pool. I will never forget the friends I made at Anamaya--they cheered me on, lifted me up, and listened without judgement. The Room: I stayed in the Lotus Room and it was absolutely stunning. The location was very convenient, as it''s just below the main house. The room was bright, clean, air conditioned with wifi, and very nicely decorated. The bathroom provided everything I needed. One thing to note: you are in the jungle, so you may have some jungle creatures stumble into your room: ants, lizards, and the like. It''s part of the experience. It didn''t bother me a bit. The room has a safe, a private porch with hammock, and windows with screens if you want a natural breeze. I don''t think there is a bad room in the whole place. The trip: Getting to Anamaya from San Jose required some planning, but it was very smooth. I opted to take a shuttle (about an hour) to Jaco, and a high-speed water taxi from Jaco to Montezuma. The boat was very cool, and pulls you right up to the beach in Montezuma. It will stop for dolphins and other cool marine life if spotted. The Retreat: Lola Rephann is a phenomenal yoga instructor. On top of the two yoga classes a day, she also led several workshops. The workshops (optional) were awesome and insightful. I will never forget watching the steam rise from the water fall and watching monkeys while doing yoga. The phrase, "Open your heart to the Pacific" is forever engrained on my mind. The view from both yoga decks is simply spectacular. There is no other comparison or words to describe. The Spa: I received a spa treatment almost everyday. There''s a wide variety of massages and services. The spa staff is wonderful and highly skilled. The Staff: The staff goes above and beyond in every way. From the many emails I sent in preparation for my trip, to making sure I had everything I needed, the staff went above and beyond. Shout out to Tony and Grettel! Everyone was very friendly and accommodating. Overall: It''s been 5 months since my trip to Anamaya and I still think about it every day. Heck, I even dream about it. If you are on the fence about going, don''t think, just go. It will change your life.'),
  (69, 'r733407217', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r733407217-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Simply an amazing place and experience!', 5, 'December 2019', NULL, 'We had the Ananda Room. It was like being in a movie. Every morning we awoke to the beautiful sunrise. Banyan Gallagher the yoga instructor was amazing, intelligent, gentle, helpful, mindful and funny. The chef Jeff was creative and prepared the most delicious meals. The entire staff was there to help and make our stay perfect.'),
  (70, 'r733375479', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r733375479-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'A wonderful week in paradise', 5, 'December 2019', 'Traveled solo', 'I booked my first yoga retreat at Anamaya. It was wonderful. Everything is well organised, staff really really nice and available. The quality of the instructor really good as well (yoga and surf). I have also discovered fantastic food. The chef is really talented. Costa Rica is an amazing country. I recommend + +'),
  (71, 'r733296310', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r733296310-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Finding my zen', 5, 'December 2019', NULL, 'I spent a week at Anamaya and it was a wonderful experience. They took care of every detail from making sure I had transportation from the airport (I arrived a day early and was staying at an Airbnb in town) They arranged a taxi to pick me up and take me to the Airbnb. They made everything easy (setting up off site activities, spa services etc.). I have food allergies and they made sure that all of the staff were aware. My food was always served on a blue plate. The daily yoga classes were great. The environment was indescribably beautiful. I could go on and on about how much I enjoyed my time at Anamaya. They treat you like royalty. I highly recommend.'),
  (72, 'r723338178', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r723338178-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Best 21 Days ever!', 5, 'October 2019', 'Traveled solo', 'I will be always grateful with Anamaya, the people that works here is amazing, kind, always there to help and serve with a Smile I did the 21 Yoga Teacher Training with Peter kaaberbøl and it was just Incredible. Since the day one I’ve been learning from him each and every day. Always in a good mood, always knowing what to teach and when. You definitely want to meet him here in Anamaya you will NEVER EVER regret. Every class is sooooooo GOOD! Don’t think about it just let him guide you to the pure, organic life. Food it’s another amazing thing that Anamaya has. Chef Jeff and his healthy, Organic food is Always surprisingly and super mega delicious. No matter if you are having breakfast or Dinner. 5 meals of the day are just outstanding. Anamaya will be ALWAYS in my heart. This place needs to be known for everyone that want a positive change of Life.'),
  (73, 'r717186674', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r717186674-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anamaya is a very special place!', 5, 'October 2019', NULL, 'We were greeted warmly and offered fresh coconut milk upon arrival. We were made very comfortable from the beginning. Yoga spaces are awe-inspiring, the treehouse is a beautiful space to spend a week!'),
  (74, 'r716421197', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r716421197-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Yoga paradise in Costa Rica', 5, 'September 2019', NULL, 'Can''t say enough about how special the Anamaya Resort is. The atmosphere is super friendly, casual and relaxing which I appreciate because we (husband, adult daughter and her friend) were not looking for a stuffy hotel type of service/environment. Gorgeous setting, lovely and clean accommodations with great views, genuine staff, excellent spa treatment selection and service, great yoga classes twice a day (Banyan Gallagher....but the teachers vary from week to week) and loved the camaraderie built over the week with fellow visitors (15 guests total the week we were there). A highlight was the tour of their organic farm where all their delicious food comes from and the beach trip with all the guests and staff (surfing for those that wanted it). Will come again!'),
  (75, 'r699204968', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r699204968-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Beyond Amazing', 5, 'August 2019', NULL, 'It''s hard to put into words how magical Anamaya is. Doing yoga while overlooking the jungle and ocean and listening to the sounds of the jungle is something truly unique. Aside from this the food was amazing, each meal was better than the last. I felt so good by the end of the week. Also, the staff is amazingggg. I immediately felt like I was part of the family and that I was cared for, which was very important for me because I was traveling alone. I stayed in the casita which was lovely. The outdoor shower is amazing. I would definitely recommend the massages, they were unreal. Last but not least my yoga instructor Cristiane Machado!! She is such a wonderful human being who helped me leave Costa Rica with a new sense of self. She made this experience into more than just a yoga retreat with her wisdom and guidance about being your true self and living up to your potential. When I go back I will make sure it is with Cristiane! All in all, most wonderful experience with no complaints. Life changing. Thank you Thank you!'),
  (76, 'r698344018', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r698344018-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Stop Researching. Book Now. It’s Amazing.', 5, 'August 2019', 'Traveled as a couple', 'Unreal experience. As adults we are always taking care of someone or something and for once, WE were taken care of. Authentically and beautifully, in every way. Tears, silence, nutrition, nourishment, adventures. Our souls are healed. Our instructor Zarelly was unbelievable and every single person generally provided the highest form of hospitality you can imagine. Our room was comfortable (and had AC) and the outdoor shower was magic. There’s even an amazing waterfall where you can jump in and swim only 5 min walk and getting into Montezuma is a lovely 15 min walk. It’s divine and exceeded all of my very high expectations. I haven’t even talked about the food yet!! You could easily go just for the food it was that spectacular. Farm to table perfection.'),
  (77, 'r696330484', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r696330484-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Magical place', 5, 'August 2019', NULL, 'I stayed here with my friend and I must say that I had an epic experience. Came here to Montezuma to surf and also have a great time. The food was absolutely delicious and the place is full of local animals and also it is in a very untouched state. The room where we stayed had a great view of the ocean and we were waken up every morning by the monkeys. The staff is also extremely friendly and very helpful. 10/10 place. 100% recommended.'),
  (78, 'r695062175', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r695062175-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Concerns', 3, 'August 2019', 'Traveled solo', 'I have stayed at Anamaya before and would have rated in 5/5 before and was the reason why I came back. However, with my recent visit I am shocked to see that one of the guests sustained a dog bite and the staff was not phased by it and did not offer medical attention. When I bought this to the staff they were seemed unconcerned and stated there is nothing much they can do but maybe arrange a taxi to the nearest doctor. Given that this retreat is in the jungle with wild animals everywhere and offering adventure packages I worry that they would not be able to provide basic help in a scenario something where to go wrong. Minor in comparison, I booked a massage and the therapist cut it short then awkwardly came to my room to apologize saying she needed to go home but could finished the massage another day? It was a very odd experience. Front desk staff where rude and abrupt at times. Overall, the food, accommodation and yoga were good but few basic things need to be straightened out.'),
  (79, 'r692261851', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r692261851-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Wonderful experience!', 5, 'August 2018', 'Traveled solo', 'A lot has been said about this amazing place. Wonderful connection with nature, amazing food, warm people... you name it! The only thing I want to add is that Watsu with Ana is a must do. When you arrive you’ll meet the staff and you will be introduced to the list of activities available. I would strongly recommend you go for watsu and that you book early if you can. This is because it is done in a natural pool by the sea and if it’s rainy you will have to reschedule. So the sooner you book, the more chances that you will be able to do it before you leave the place.'),
  (80, 'r687249642', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r687249642-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'This place deserves 10 out 5 stars! Be prepared to feel completely wrapped in love when you stay here.', 5, 'June 2019', 'Traveled solo', 'Anamaya holds a very special place in my heart. I went there between the dates of June 8-22, and was not expecting to leave the resort with such a heart-opening and life changing experience in such a short amount of time. For one, it felt as though this place had been designed especially for me. Every detail in the experience was perfect. Every single moment was perfect… it felt as though they read my mind and knew exactly what was perfect for each moment in the experience… for example in Garuda’s Nest the table runner from Guatemala was in my favorite colors…also one day I was craving plantain chips…didn’t say anything to anyone but they magically showed up on my salad moments later…every single moment of each day was like that. The caring and loving staff, breathtaking views, the saltwater pool, the landscaping, the design of the rooms, (I stayed in Bali the first week then switched to Garuda’s nest the second week-- both rooms are outstanding by the way, highly recommend), the healthy, nutritious, savory meals (they perfectly accommodated my vegan diet), the classes/activities provided, even the visiting yoga teacher Zarelly Caneles and her classes. The yoga teacher Zarelly Caneles was the perfect yoga retreat teacher for me. After suffering a back injury last year, I’ve been recovering from that process using primarily alternative health practices and physical therapy. Zarelly is an alternative health physical therapist. I could not have asked for a more perfect person to be my yoga teacher. She is a wealth of knowledge of anatomy and yoga philosophy, while also being a responsive teacher to her students. She was able to seamlessly give every student in class exactly what they needed while adequately challenging us based on our unique needs. I was able to push through many mental “walls” I had put up due to the injury and it felt so good to experience those breakthroughs. Not to mention, she would encourage you in a loving, nurturing but firm way. She also developed an environment with her students that allowed us to bond in such strong and powerful ways. I felt so close to the people in the retreat and it was impressive to witness her facilitate that environment in such a short time. Her cacao ceremony and dancing meditation set the bar high for anybody else I may experience that with. Those were unforgettable and transformative experiences. The food. Wow…what an experience. It was delicious, beautiful, nutritious and made with so much love. They also have fresh coconut milk and almond milk too...which was so appreciated as a vegan. We took a farm tour and there is so much thought/effort that goes into what they grow and how the food is produced before it even reaches the table. Jeff (the chef) is so willing to accommodate any of your dietary needs or wishes, you always feel completely nourished with whatever he and his team present on your plate. It’s also really intriguing to witness how creative he is with his artistic expression of food on each plate, and how much he thinks like a scientist (as a science teacher I totally appreciate that). His cooking class was extremely fun, interactive and informative! The two salsa classes I took were so much fun with Cristiane and Ana Laura (separately). I felt like I was dancing with my sisters/best friends during the experience…. they both had such a welcoming and caring way to teach the class. Each of them had a different teaching style but both classes were exciting to learn and experience. I wish they taught classes near me so I would be able to attend more often! The staff all went above and beyond to make the experience extra special for each person at the resort. I have attended another yoga retreat place in Costa Rica 2 years ago and thought the service was great there…but Anamaya blows the customer service piece out of the water in comparison. They really go above and beyond to make sure every person is happy, well cared for, and wrapped in love. You really do feel like part of the family there…. For example, I have a travel altar and the cleaning staff noticed I would place flowers on it, so they would bring fresh flowers every day for my travel altar… a gesture that was so simple, yet so profound, considerate, and incredibly loving, an act that was way beyond their job description. Another example, I had switched rooms the second week and one of the owners of the resort, Joseph, was so kind to help carry my extremely heavy luggage up 2 flights of stairs to Garuda’s nest. He could’ve easily had me wait for one of his employees to carry the luggage but he was so humble and kind to do it himself. I have never met someone in a role as an owner of a business do such a caring and humble act for their customer. Both of those experiences, from the cleaning staff to the owner, brought me to tears, to experience such kind actions without any expectation in return. It really speaks volumes of the values and culture of the resort, and why it stands above the rest. I recently attended a Kriya yoga conference in Chicago and there Guruji stated, “Any work you do, everything you do, do it with love! Do all work with love, and no work is inferior…We all have to serve and love each other. Life is to live, Life is to give, Life is to love, and Life is to serve.” I truly feel everybody at Anamaya practiced this sentiment wholeheartedly. No matter who you are, they treat every person that attends their resort with such a high level of respect, like you are a guest of honor there. It really made me think about how I can create the same experience for others in my own life as well. Accommodations that should be mentioned…there is WIFI and air conditioning in every room, which makes for an extra comfortable experience. Beds and pillows very comfortable too. My favorite aspects of Bali (besides that it was a gorgeous room) was the shower that had a private ocean view. It was so beautiful and unique. Also, the private deck with an ocean view was perfect for morning meditations…. The second week I stayed in Garuda’s nest…I pretty much got to experience a childhood dream of what it feels like to live in a treehouse. The surrounding views (3 sides) were so breathtaking (ocean, forest, ect)… words cannot do it justice you just have to experience it for yourself. I cannot imagine another place on Earth like that…perhaps one day I’ll build a house like that. Spa services…. all were fantastic. I did various massages and all were expertly done and very therapeutic/restorative, the therapists were very in tune with their client and had a very intuitive flow about their practices. I highly recommend those too! At the end of the week they do a special dinner with a circus type performance to close the week. It was a magical experience…they had a fire dancer, belly dancer, acro-yoga performer, and a dance party afterwards. It was so much fun and such a perfect bonding experience with the group to close the week. I entered this place with the intention of healing…but left with so much more… feeling restored and renewed…heart wide open... a different person, ready to pay their mission’s efforts forward in the lives I encounter in a similar way… which is pretty incredible given it was within only 2 weeks this was accomplished. Anamaya is heaven on Earth… a place that is a feast for the mind, the heart, the senses, the body, and the soul.'),
  (81, 'r679958735', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r679958735-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Beyond incredible. Everyone should go', 5, 'June 2019', 'Traveled as a couple', 'The photos do it no justice. Everywhere you look is just beyond beautiful. Doing yoga on the yoga deck hearing howler monkeys, looking out at the ocean and the mountains was something I''ll never forget. We stayed in the Bali Cabina and that has by far been the absolute most amazing place I''ve ever stayed. The outdoor bathroom with an ocean view (and a giant bath tub) was so awesome. The pool is so great and the food was super amazing! We even went fishing and chef Jeff made a variety of stuff with the fish we caught for everyone to share. It was great! They had salsa dancing and a cooking class too amongst other things. We did a few day long tours though and it was all great. The staff set those up for us and handled everything. Laura was incredibly helpful and so sweet. I cant say enough good things about our stay. I came here after 4 years of traumatic life changing experiences and this was everything I needed to reset and take a breath and move forward. So magical. You really make a lot of new friends and I loved us all sitting by the pool at night sharing wine and stories. Downtown montezuma is super close so we walked down and the breweries, beach, and bars are a lot of fun. Just a really great spot.'),
  (82, 'r678698709', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r678698709-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Breakfast', 5, 'June 2019', 'Traveled on business', 'Great atmosphere and interior design. Service here is excellent, proactive, and sincere. Food quality is nice as well. Special thanks to Shweta nikhil avnish ND Aman, they took very good care of us. We had a great time!: )'),
  (83, 'r678784989', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r678784989-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Magical Yoga Retreat', 5, 'May 2019', 'Traveled with friends', 'Where to begin?! Anamaya is truly a magical place - the resort is beautiful and the connection you make with the staff and people at the retreat is really like family. I am impressed with how quickly the staff remembered our names considering retreats are held there regularly. The staff is also very communicative from the first e-mail I sent to them up until I arrived. Everything was organized, thorough, and seamless! THE FOOD! Wow. Every meal I had was amazing and is locally sourced at their nearby farm. Go Chef Jeff & his team! Can I hire them to cook for me everyday?? Even though it was raining the first few days, it really taught us to slow down and really enjoy the simple moments. I ended up getting two massages, one of which was the LOMI LOMI (with the hot oil massage). It is a MUST. And I also got a tarot reading from Diane. Highly recommend, it gave me chills. I loved my yoga teacher, Marcela Nunez!! She is THE BEST. She is so thoughtful and detailed with her practice, really thinking about how one poses flow into another. She is also very attentive to our bodies and alignment. I''m not sure if I''ll ever find a teacher quite like her as she set the standards so high now. Everything was perfect except for one minor thing. I have to point this out. The mosquitoes! I am all for natural insect repellent but they are immune! Make sure to bring some heavy duty mosquito repellent. One of my friends used picardin and she didn''t get bitten like the rest of us (we were ravaged). If you''re looking for nightlife nearby, hit up Chico''s. If you have more time, there are many restaurants and bars in Santa Teresa! So fun. Overall, I highly recommend this resort to anyone! Everyone! It is a life changing experience and I will cherish it forever!'),
  (84, 'r677365895', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r677365895-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Yoga Retreat Anamaya', 5, 'May 2019', 'Traveled with friends', 'This was a trip of lifetime. Accomodations are fantastic. We had group of 5 girls and stayed and Gia. Lots of room, great bed, open showers, AC and great service. Food was amazing. Morning with sunrise and evening with sunset - yoga with Selena was a dream. At night you can hear howling monkeys in the forest, during day you see iguanas and birds. Flowers blooming everywhere. Pacific ocean warm and beaches full of shells. Staff will accommodate any of your wishes and chef Jeff knows his cooking. If you are looking for night life just walk to town.If you want to relax this is the place to be. Oh I almost forgot. Massage is a must - Lumi Lumi was my fave.'),
  (85, 'r677328311', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r677328311-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Went for my ytt training.', 5, 'May 2019', 'Traveled solo', 'Anamaya is a magical place! Everything from the staff to the food to the rooms is top notch! The staff really becomes like family to you! They take the time to get to know you and they really care about your time there. The rooms are beautiful and kept so clean! The food is unlike anything I have ever had and all comes from a farm. When it came to traveling, the staff was a life savor! They booked my flight for the Sansa airline and called us taxis when we we needed them! Everything was unreal and absolutely amazing.'),
  (86, 'r670467152', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r670467152-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Love is in the details!', 5, 'April 2019', 'Traveled solo', 'This resort is spectacular, breathtaking and there is a beautiful energy quality there, that is difficult to put into words... I can''t express how grateful I am to have been able to have the experience I had, an Anamaya... The people that run the resort truly become like family and they stop at nothing to make sure your experience is unforgettable. I have travelled all over the world and I have to say that Anamaya is my favourite place, and I can''t wait to go back. If you go, you need to try the reiki with Diane and the Lomi Lomi massage. I would recommend this resort to anyone, you will not be disappointed!'),
  (87, 'r668666444', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r668666444-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Yoga retreat at Anamaya', 5, 'April 2019', 'Traveled solo', 'All I can say is WOW! excellent service, clean rooms and a life changing experience. I was hesitate to go on a yoga retreat but after my experience at Anamaya I am forever grateful I took the chance. The combination of yoga, meditation, clean eating and fun activities was perfect. Bring sun screen it gets hot in Costa Rica.'),
  (88, 'r664025751', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r664025751-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Lomi Lomi 4 Life!', 5, 'March 2019', 'Traveled solo', 'Where to begin......I was physically unable to stop smiling for the first two days while I processed how amazing and beautiful this intimate resort was. What I would give to start every single day by waking up to sunrise and the sounds of nature, eating fresh fruit, and doing yoga on the most beautiful sundeck ever created overlooking the ocean and jungle. The schedule is the perfect balance of yoga, rest, relaxation, and activities. The staff is extremely charming, attentive, and helpful. The warmth and comfort they provide makes it feel like you''ve known them for years. Every meal I would say this is the best meal I have ever had, just mind boggling. Chef Jeff slays and the farm is also very cool. The ultimate kicker was the Lomi Lomi Four Handed massage, a must do here. One of the craziest experiences of my life. Anamaya is heaven on earth.'),
  (89, 'r663834649', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r663834649-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Relax.Recharge.Renew', 5, 'March 2019', 'Traveled solo', 'Exactly what I needed! Escape to paradise to relax, renew and recharge after a hard start to 2019. What I did not know I would come out with was the awesome new passion for yoga -thanks to Kelly and Ted, meditation as a daily practice, healthier eating habits, and a new family of lifelong friends and connections. The food is amazing, the entire staff are extremely friendly and helpful, and the property is unbelievably clean. LOVE! I cant wait to go back. Marcy'),
  (90, 'r659931950', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r659931950-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Magical Place', 5, 'February 2019', NULL, 'Magical is the only word I have to describe my stay at this amazing and intimate resort! Everything from the friendliness of the staff to the cleanliness was perfection. Shout out to Malissa Whited! Best Yoga teacher ever! The food was not only delicious and healthy it was always creatively presented. Kudos to the chef! We were greeted every morning with platters of fresh fruit to have before our morning yoga session and breakfast was served afterward. Lunch, late afternoon snack and dinner after an evening yoga session made for pretty special days. Most time in between was spent lounging around reading or chatting, checking out the local waterfall, Anamaya''s organic farm or traveling a short distance to the sweet town of Montezuma. Blissful! Highly recommend Anamaya for a very special yoga retreat!'),
  (91, 'r658357282', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r658357282-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anamaya amazing', 5, 'February 2019', 'Traveled with friends', 'This place is magic. I arrived mentally and physically drained. After a kind staff, magical place, epic food, beautiful views, amazing service, memorable massage, a nurturing community, transformational yoga, and mind blowing accommodations, I came home a new and better person. It opened my mind, my hips, my soul, and my perspective. One of the best vacations I have taken for myself. The reality was even better than the photos. I have a tree nut allergy and they were super careful and conscientious about taking care of me, making me special meals when needed. Highly highly recommended.'),
  (92, 'r658281196', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r658281196-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Return to Your Heart at Anamaya!', 5, 'January 2019', 'Traveled with friends', 'Most relaxing + rejuvenating trip I have ever enjoyed!! The food was farm fresh, organic, gluten free and best of all... absolutely delicious. My healing massage in the jungle spa was amazing + worked a knot out of my shoulder that had been there for months. Our yogi, Natasja Payne, provided insightful yoga classes combined with Ayurvedic teachings that nurtured our bodies + souls. Returned home feeling thankful + blessed to be a part of this experience we call life.'),
  (93, 'r656915693', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r656915693-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Peaceful Paradise', 4, 'February 2019', 'Traveled with friends', 'Just got back from a week of yoga, surfing and relaxation at Anamaya and I wish I could be back there right now! From the first hello to the (almost) emotional goodbyes, we were made to feel a welcome part of the family. Food was very varied and very good. Chef Jeff is very good at coming up with different, interesting and tasty, healthy dishes. We stayed in the Bali room, which offered an amazing view of the coastline while being nicely tucked away behind the main house. All the other accommodations were built to very high standards too and all of them had great views. We specifically timed our stay to have Silvia Eriksson as our yoga instructor for the week. You couldn''t ask for a nicer, more competent and caring yogi. Sadly, she only does a week a year at Anamaya, but she does teach at other places in the village, which is a 15min walk down the hill and also has a range of shops, bars and restaurants.'),
  (94, 'r651723003', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r651723003-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'dinner at annamaya', 5, 'February 2019', 'Traveled on business', 'service by sonam os excellent. she did a great job l love the service .love the hotel.thankz to all. i love the butter choken and briyani n chicken tikka cold meze platter is really nice love the chef prepation'),
  (95, 'r648348999', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r648348999-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Sonali', 5, 'January 2019', 'Traveled as a couple', 'Loved the butter chicken .. chur chur naan ... loved all the staff .. very polite .. kind .. fast service ...staffs are super comfortable friendly ... loved the service ..ambience ..all organic concept... special thanks to Komal .. she is such a sweetheart n took care of our order and took feedback.. informed us about the concepts of organic ... thinngs.. wat Andaz all about .. one more thanks to Karan .. he was sweet and polite n cute smile !! 😁😁😁 so guys visit this place ....'),
  (96, 'r644107017', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r644107017-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Perfect in every way', 5, 'December 2018', 'Traveled with friends', 'It''s hard to describe something so pleasing on the eye, set in a truly stunning location with panoramic views that are breathtaking - whether you are watching wildlife in the trees or in the air, sunrises or the moon sparkling on the ocean. Being surrounded by nature is good for the soul, as is the food served at Anamaya which is healthy and plentiful. There are plenty of places to relax in the sun or shade, the pool is a pleasant way to cool down and stare at the ocean. The yoga teachers, Kelly and Ted, were a joy. The reservations and reception team, gardeners and housekeeping staff were so friendly it was like staying with friends and nothing was too much trouble. I needed help in salvaging my holiday from the Gatwick drone debacle and once there, I extended my stay and was provided with assistance in finding accommodation at the busiest time of year. I can''t commend the staff highly enough, so friendly but also highly professional at ensuring everyone enjoys their stay. I stayed in the Mantra Room, which is probably one of the furthest rooms from the main house, so a fair amount of steps to climb, but set immediately beneath the yoga shala used in the evening. It had an indoor bathroom (many are outdoors/open air) and faced the jungle, it was simply furnished compared to other rooms but perfect for me, preferable to sharing. I have such lovely memories of my time at Anamaya over Christmas. I slept what is considered a healthy amount every night whilst there and I rarely get more than 4 hours unbroken sleep so I returned home feeling totally refreshed. I will definitely be returning!'),
  (97, 'r642616453', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r642616453-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing location, incredible views.', 5, 'November 2018', 'Traveled with friends', 'A totally unique place to stay and explore Montezuma, Costa Rica. Loved the planned activities and yoga schedule. The food was delicious and conscientiously prepared.The staff was fun and interactive. The setting was spectacular. It was nice having a “group family” to share experiences with. The infinity pool and yoga studios were tops. The property was well kept and the grounds were lovely.'),
  (99, 'r642220925', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r642220925-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'We loved Anamaya!!!', 5, 'December 2018', 'Traveled with family', 'We couldn’t have asked for a better place for my mom and I to spend a week relaxing and doing yoga. Everything from our room, the grounds, the yoga decks, and pool were beautiful. Our meals were delicious and always fresh and organic. Not having to worry about your next meal and just enjoying your time totally made the trip more enjoyable. The staff always had smiles on their faces and made sure we were always taken care of. Lola, our yoga and meditation instructor for the week was beyond our expectations. She helped us to grow and deepen our practice so much during the week. I do believe we will be coming back sometime soon!'),
  (100, 'r641292400', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r641292400-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Most beautiful, relaxing, and wonderful place I''ve ever been to', 5, 'December 2018', 'Traveled solo', 'I just returned from a one-week yoga and surf retreat from Anamaya and could not possibly recommend this place more to anybody, no matter their particular interests. 1. Facilities: The yoga deck is the most beautiful place I have ever practiced yoga. It overlooks the ocean and the jungle with frequent sitings of wild birds, monkeys, and other wildlife. It is situated above a cliff so that the view of the ocean is unparalleled. The infinity pool is always crystal clear and clean also overlooking the ocean and is the perfect place to relax and read a book. The main house is a lovely place to hang out with the other travelers with lots of nooks with pillows to relax and chat or just take a nap. The dining area is also perfect for socializing or taking time to yourself while you have one of the incredible meals that Anamaya has prepared 2. Food: The food is unbelievable. At home I never restrict myself to any sort of blank-free diet. At Anamaya the diet is gluten-free, dairy-free, and largely pescaterian with a few chicken dishes scattered in there. I had absolutely no complaints and in fact adored the food. It was healthy but tasted rich with so many varieties of flavors and textures. The hot sauce was particularly good as was the coffee every morning. They food you CONSTANTLY so you are NEVER HUNGRY and you can skip meals if you wish of course. I have no dietary restrictions however some others in the group did and Anamaya did an incredible job catering to their very, very specific needs. They would set aside food for them and create entirely different dishes for them so that they could also enjoy the meals. Another wonderful part about the food is that it is all locally raised and grown. We even visited the farm where a lot of the food comes from and it was so much fun. Also, one day two of the travelers caught 2 giant fish on their fishing tour and the chef cooked them for dinner! Nothing is fresher than that. 3. Yoga: The yoga was perfect. We had 2 sessions per day (but you can attend as many or as few as you wish) with the AM session more vinyasa-style and the PM session more restorative/yin-style. I have been practicing yoga for ~10 years and there were others who had practiced even longer or were instructors. The students'' experience varied widely, however, and many had never even set foot on a yoga mat. Our yoga instructor, Miranda, was very cognizant of this wide array of experience and ensured that the classes were all-level while giving us different variations if we wanted to try new things. All of this being said, no matter what level of yoga you are at whether total beginner/never tried before to yoga instructor yourself (we had 2 in our class) you will get something out of this. 4. Surf: This was the absolute best surf instructor experience I''ve ever had. I''ve surfed in 3 different countries and always with an instructor, and these instructors have been the most patient, caring, supportive ones. They celebrated your successes and helped make tweaks to your form. Again, there were people who had NEVER surfed in their lives to people who have surfed around the globe. The instructors split you up in groups of 1-3 people per instructor so you always got exactly what you needed out of the time there. The beach we went to, Playa Grande, was absolutely perfect for beginner-intermediate and if you were more advanced you could go to a different beach or try the waves at Playa Grande. The beach was perfect because we had to walk 10-15 mins out so that there was basically nobody there except for us. Unlike other places in Costa Rica, this beach is also quite secluded so there are no high rises, no condos, no big hotels in the vicinity. Behind the beach is just jungle. One day we saw 15 monkeys hanging out in our break spot! I could not have asked for a better surfing experience. 5. Staff: The Anamaya staff is unlike any other staff I have ever encountered. I know I keep saying this in each of the other list items but it''s true. From the first email I sent them I knew they would be communicative, honest, and so speedy in their responses. I always received an email back within MINUTES of me sending one, instilling trust in me that this was a place that actually cared about their people, not just the money. When I got there the staff had arranged taxis for me that arrived promptly, and they greeted me warmly with a cold coconut upon arrival. They ensured that I was extremely aware of all of the options for adventures and activities as well as the prices. They are unbelievably organized and never missed a beat on anybody''s plans or goals for the week. They are warm, friendly, experienced, and caring. They learned EVERYBODY''S names and where they were from even before you stepped foot in the door. They were always available and just the most loving people ever. An anecdote: When traveling back from Tambor to Liberia to catch my flight I had booked a Sansa flight. Through no fault of Anamaya, the sansa flight was cancelled last minute and we had already arrived at the airport. Sansa did not even call, text, or email us about the change! It was of course very distressing at the moment since we all had flights to catch at Liberia and driving would have taken hours and hours. Not only that, but we had used all our last cash that morning since we were coming back to the US. So without cash and with very little time to spare we hired a cab and planned to get money at the airpot. Of course by the time we arrived (thank you to the cabbie who SPED to Liberia to get us there in time) the ATM was malfunctioning! I had no idea what to do with only minutes to spare and no money to pay our very kind taxi driver. I immediately knew I could count on Anamaya to help us. I called them and they helped arrange the taxi driver to pick up the money with them. This is absolutely not a responsibility they needed to take on and I am endlessly grateful for them bending the rules to allow me to do this. It is a perfect example of how Anamaya cares deeply about their guests and their experience from before-start to after-finish. 6. Travelers: The fellow travelers were also a delight to have on the trip. The age ranged from 18-50s with the mode probably in the late 20s early 30s. Everyone brought something different to the table and got along very well. The majority of people on my trip were solo travelers along with a couple of couples, sisters, and mother-daughter duos. Everyone came for their own reasons that we shared at the beginning of the trip together and we all became so close by the end. 7. Massages: The options for massages was unending! I never knew that many of these massages even existed and every single person who got a treatment said it was the "best in their lives". The Eastern head and neck was so relaxing and the body scrub left me the cleanest I have ever felt! I highly, highly recommend getting a massage while you''re there! Before I came here I read the couple of reviews that were not 5 stars (they are RARE) just to see what people had complained about. I can CONFIDENTLY say these are either misguided or the staff had immediately fixed the problems. I have literally zero complaints. I know it''s hard to believe but this it an incredibly perfect, wonderful, relaxing and adventurous place. I never travel the same place twice but I would come back in a heart beat. Thank you Anamaya for the best experience! Jessica'),
  (101, 'r638973548', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r638973548-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Magic', 5, 'December 2018', 'Traveled solo', 'It''s hard to put into words how special and magical this place is...if you are considering it just go! The setting is so unique surrounded by the Pacific ocean and jungle. It feels more like home than a resort. The staff go above and beyond so everything is taken care of and you can just totally relax. The food is delicious, healthy, creative and I looked forward to every meal. The daily set up works well with yoga in the morning and evening and then the day is yours and there are so many activities available so you can chill out for the week and do nothing or you can go and have plenty of adventures, you make it whatever you need. I was fortunate enough to be on a retreat led by Abbe Ciulla who is such a talented teacher and with her positive energy we were all one big family by the end of the week'),
  (102, 'r636331178', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r636331178-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing place, amazing experience', 5, 'November 2018', 'Traveled solo', 'Wow, not even sure how to write a comprehensive enough review for Anamaya! I stayed for a week-long retreat in early November. I knew I would be traveling solo, so I was really looking for a place where I could have some excitement (ziplining, surf classes, waterfall hikes, etc.), relaxation and spa treatments and actually get to know other people within more of an intentional community than a normal "resort". Anamaya provided all of this and even more. I don''t normally do yoga in my day-to-day life, but I wanted to give it another try, and I ended up really loving the classes at Anamaya. Our instructor for the week, Cassandra Wilder, was amazing and super helpful, and of course the outdoor yoga decks overlooking the coastline and jungle did not hurt! Cassandra also led a series of three workshops for anyone wanting to attend, which really added to the atmosphere of personal growth and peace. As all of the other reviews mention, the food was AMAZING. I don''t normally eat dairy or gluten free, but I really enjoyed not only eating so cleanly, but also just seeing what kind of unique, refreshing meals can be made without dairy and gluten that aren''t just boring salads. I stayed in the Mantra room below the second yoga deck by myself. It was a nice size and always clean - there were lots of stairs to climb up and down to get to/from the room, which I didn''t really mind, but it''s something to keep in mind if you can''t get up stairs easily. The staff was always so friendly and helpful and made a real effort to learn everyone''s names. It really did feel more like staying at a new friend''s home instead of a hotel or typical resort. The final thing I would say is that the other reviewers are totally right - there is something indescribably magical about Anamaya. I was definitely in need of some personal searching and growth, and part of me doubted how much could happen or change in a week, but I left Anamaya and Costa Rica feeling so much more grounded, at peace, excited and hopeful for the future than I could have imagined. I will definitely be back in the future!'),
  (103, 'r620004642', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r620004642-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Words cannot sufficiently describe how incredible this place is', 5, 'September 2018', 'Traveled solo', 'I have just got back from a 3 week yoga teacher training at Anamaya and I honestly cannot put into words what an incredibly special place Anamaya is. This is one of the rare places where the photos genuinely don''t do it justice. *The location is truly incredible and you will be joined by all manners of wildlife throughout your trip. There is honestly no need to ever leave Anamaya during your stay if you don''t want to! *The food is absolutely to die for - you definitely won''t go hungry and you will be consistently amazed by what the kitchen rustle up for you. *Above all, the staff at Anamaya are truly amazing. It sounds cliche to say they are like a family but they really are and the way they welcome every guest into that family is so heartwarming. I had a very difficult time leaving Anamaya and without a doubt will be back! I am now worried no other yoga retreats/courses/trainings are ever going to live up to what I experienced at Anamaya...'),
  (104, 'r614949678', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r614949678-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Feels like Home', 5, 'September 2018', 'Traveled as a couple', 'Just spent one week in yoga retreat. Place is remote but worth the trip. Food is gloriously delicious and truly healthy, fresh, gluten free. Jeff, the chef is as creative to use farm ingredients wisely with health in mind. Yoga is amazing and the views spectacular. Messages are the best I ever got. Recommend lomi lomi and deep tissue. Employees give the extra mile to please you, and make feel like home.'),
  (105, 'r609526554', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r609526554-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Best retreats in Costa Rica', 5, 'July 2018', 'Traveled with friends', 'If you are into amazing views, magical happenings, the best food, incredible people and a place that will change you forever, then this is your place! You deserve this! It is Awesome and we will be back.'),
  (106, 'r601168335', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r601168335-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Not enough words to describe this piece of paradise and it’s people - Anamaya!', 5, 'July 2018', 'Traveled solo', 'I visited Anamaya 5 years ago, and said I would visit again. Was there two weeks ago and I already miss it. The location is to die for. In the middle of a mountain, surrounded by lush green vegetation. The air u breathe is a pure as can be. Still easy to get there and back. U can choose, small plane, ferry, bus or car. On site expect to be surrounded by beautiful flowers, moroccan chandeliers (lamps), buddhas and an incredible group of people to make your experience a memorable one. Everyone there was kind, helpful, very warm hearted and professional. They all take customer service to another level. Anything you may need or want, they will make it happen. Albert, Ana Laura, Lura, Antonio, Coquito, Grettel, Chef Jeffrey and all of those on site work in synchronicity to bring us guests a seamingless pleasurable experience. The facilities are not only unique and beautful but very well thought of. Each room has its own individual touch making them all very special but different at the same time. Beds are very comfy. The colors, the furniture, the layout of the spaces makes it to where you can enjoy the groups company or be on your own if you wish to. The food was very delicious. Everyday we had something different. You could taste the freshness of the ingredients and tell the food was prepared with a lot of care. I appreciated their ability to accommodate to your diet needs. Perfect place to clean and detox your body. If u r not vegetarian, here you can get a good taste of how yummy vegetarian food can be ;) Our teacher this week was Veda Ela, I dont have enough words to describe what a beautiful soul she is. She not only teaches yoga but she lives it, making me feel completela submerged in the practice on and off the mat. Her knowledge of mind, body and spirit permeated my whole experience at Anamaya. She was open, free spirited and with a beautiful smile that radiates whereever she was. Thank you Anamaya for having her. I would totally go back and take another class with here. Usually I don’t wrote reviews this long but felt Anamaya was worth every word written here. Thank you everyone at Anamaya for making it feel like my home away from home. Can’t wait to be back 🙏🏻'),
  (107, 'r594602835', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r594602835-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Making a Mind, Body & Spirit Connection', 5, 'June 2018', NULL, 'Anamaya Resort & Retreat Center is the best money I have spent on a vacation. And it was so, so much more. I left here so relaxed, restored and rejuvenated after my 7-day adventure that I even went back to my stressful television job early. Yoga Teacher Jacqueline helped me make all kinds of breakthroughs. The yoga classes were excellent. Manageable for a beginner and challenging enough for regulars. The spa treatments were excellent especially the deep tissue massage. The staff was super friendly. And the views were breathtaking. The waterfall hike was perfect. I did it almost every day! Go ahead and book. You won''t regret it.'),
  (108, 'r578565337', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r578565337-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Anaymaya exceeded all expectations.', 5, 'April 2018', 'Traveled with friends', 'Food, staff, accommodations was beyond amazing. The overall experience was 10/10. Our yoga instructor for the week, Cristiane Machado was inspiring, motivating, engaging, and just created a presence that made the week so special. Will definitely be going back!!!'),
  (109, 'r578557322', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r578557322-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Yoga retreat', 5, 'April 2018', 'Traveled solo', 'The retreat was more than I expected. The instructor, Cristiane was amazing, funny, compassionate. The classes were adaptable to all levels, from no experience to the pro. I hope to visit again and enjoy Cristiane classes, Namaste ❤️❤️❤️'),
  (110, 'r576258848', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r576258848-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Wonderful place!!', 5, 'December 2017', 'Traveled solo', 'This was my first trip, and I went solo! I searched for yoga retreats for a while and decided on Anamaya because Costa Rica was on my bucket list. Let me tell you, Anamaya did not disappoint! Food, amazing. Views, amazing. Everyone that works there is very friendly and there to help with anything you may need. The other travellers I met there were such an amazing group of people. A few of us are even planning a trip back together!'),
  (111, 'r572759379', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r572759379-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Perfect Yoga Retreat', 5, 'May 2017', 'Traveled with friends', 'I don’t have enough room to type a proper review. I traveled with a couple of other friends for a yoga retreat and attended many fun excursions. The rooms were simple and perfect, but the outdoor bathroom was purely a treat. The pictures do not do this place justice. The yoga shala overlooking the water and jungles in the evening, with a thunderstorm rolling in, is like nothing we have ever seen...breathtaking. The food was beyond what we expected. The staff was incredibly friendly and asked daily if we had any needs. We’ve attended several retreats together since and all agree none have yet provided the quality Anamaya does. I do believe that the yoga host can make a huge difference, so research your hosts prior to choosing your week. I don’t think you’ll regret your decision to go. I’ll definitely be back.'),
  (112, 'r569794893', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r569794893-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Would Definitely Come Back!', 5, 'March 2018', 'Traveled with friends', 'Anamaya and the staff are amazing! My friends and I went for a yoga and surf retreat and came back with way more than we expected. The greatest part of Anamaya is that you can go there to relax and do nothing else but read by the pool or fill your time with as many activities as you would like, completely up to you. The staff are so kind and fabulous that I left feeling like I have extended family. The other guests who were there when we were there were wonderful so we made lots of new friends. The food was A-mazing, healthy and all dietary needs met. The yoga classes were a great workout in the mornings and rejuvenation in the evenings. The property was incredible, not over-the-top fancy rooms, perfect for that atmosphere, clean, comfortable, cool, with great views. The outdoor shower and bathroom was the best experience, especially at night, under the stars! Look no further, you will get more than your money''s worth at Anamaya!!!'),
  (113, 'r568914766', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r568914766-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Costa Rica Adventure', 5, 'March 2018', 'Traveled with friends', 'My Friends and I loved Anamaya! The property and housing was Beautiful, but not immaculate. The staff was wonderful. They were very helpful, and super organized! I loved all of the additional activities that they helped coordinate daily. The food and snacks were also FABULOUS! I wholeheartedly hope to be able to return with my family and friends again in the near future. Thank you to everyone who made our trip Wonderful.'),
  (114, 'r566061016', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r566061016-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Wonderful resort - excellent Yoga Teacher training', 4, 'January 2018', 'Traveled with friends', 'I spent three weeks here in January taking Paula Tursi''s yoga teacher training, which was beyond excellent. The resort itself is utterly beautiful, set amongst nature but with a high level of luxury. The yoga decks and provisions were perfect, as were the staff who were all so friendly and professional. I was lucky enough to have a room with a semi outdoor bathroom and a private terrace with a hammock. This meant I could shower whilst watching whales in the ocean or see the stars without light pollution, and every morning saw the sun rise from my hammock. It was heaven. The animals were amazing - howler monkeys in the morning, Toucans watching the yoga practice, and sloths. My only criticism was the decision by the owners of the resort to condense the four week training course into three weeks as they did not have enough people signed up. I felt this was done purely for monetary reasons and was not of benefit to the students or to Paula and her wonderful co-teacher Taylor. For this reason I would suggest finding a 4 week training course if you are considering becoming a yoga teacher. But I would definitely recommend Anamaya as a holiday destination.'),
  (115, 'r566037605', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r566037605-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'paradise', 5, 'April 2017', NULL, 'I went to Anamaya twice. The place is beautiful, the food is amazing and the on-site organization is impeccable. The staff at Anamaya are fantastic and attentive to your needs. I slept each time in a large room shared with 4 or 5 other people that I did not know and it''s perfect. For yoga classes, I recommend Lucy Hammel''s classes. This teacher is really great. The surf lessons are totally adapted to the beginner level and the teachers are very serious.'),
  (116, 'r565272378', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r565272378-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'There is a genuine warmth you feel from the staff', 5, 'February 2018', NULL, 'Liked everything about Anamaya. Anamaya is a beautiful place. Food, yoga, excursions, spa, circus performance: all spectacular. But what makes Anamaya a truly amazing and magical place are the staff. You are greeted each day with smiles and hugs. There is a genuine warmth you feel from the staff, who go out of their way to make your stay amazing. By the end of my week I felt the staff were part of my family and myself part of the Anamaya family.'),
  (117, 'r561606664', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r561606664-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Absolutely heavenly', 5, 'February 2018', 'Traveled as a couple', 'This place is fantastic!!! Gorgeous grounds, fantastic people working there, the food is unbelievable. It is so much more than just a vacation. I will definitely be back and I never go to the same place twice.'),
  (118, 'r560046375', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r560046375-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Incredible', 5, 'February 2018', 'Traveled with friends', 'I cannot recommend Anamaya highly enough. It is incredible in every way. The property is gorgeous. The rooms are clean and beautiful. Some have outdoor showers, which is such a luxury. The food is so healthy and delicious - much of it is grown on their nearby farm. The yoga decks had the most amazing views. I saw multiple animals from the decks. The yoga classes themselves were terrific. The arranged tours and adventures - like surfing and zip-lining - were fantastic. One of the most wonderful things about Anamaya was the staff. Each and every one of the staff members were so kind, helpful, patient, and cheerful both before and during my stay. They helped arrange multiple modes of transportation to and from the retreat. One staff member even went so far as to bring me medicine from his own house when I asked if it was available at the retreat. I was so grateful. I wish I never had to leave!'),
  (119, 'r559900425', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r559900425-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing spot for a yoga retreat!', 5, 'January 2018', 'Traveled with friends', 'A friend and I booked a Yoga and Rejuvenation retreat for a week in Jan/Feb of this year. It was an amazing experience from arrival to departure. The location was an adventure to reach - I highly recommend just taking Sansa Air from San Jose airport to get to Montezuma and save yourself a long trip by shuttle and ferry (although it was nice to see some of the area along the way) The staff were wonderful and caring... felt like family after the first day! They look after every need and are customer service professionals. Check in was smooth, and we were provided with plenty of information on what was planned for the week. The show that they put on one of our last nights was excellent and you could tell by the fun they were having performing, that they truly loved their work. Our room (Hanuman) was large,bright and a perfect place to wake up to the sunrise every morning. There were two very comfortable king sized beds and a beautiful outdoor washroom - so nice to shower and look out over the jungle and ocean! The food was unbelievable... fresh and plentiful and never repetitive. They serve a gluten free, dairy free menu with many options. I took lots of snacks worrying that I would be hungry, but gave them away before I left as I never had an opportunity to feel hungry. The staff will work with any dietary concerns so, although I can eat anything, they were very accommodating to those who had concerns. They do serve fish and chicken so no worries for non - vegetarians. The yoga with Paula Tursi and Taylor Arjinder was wonderful - I was so lucky to have booked this particular week with these two spectacular instructors! I really enjoyed the daily focus on different areas of the body and the evening candlelight practices. I had an Eastern Massage and a Reiki treatment with Dianne... Both so amazing in their own way. I unfortunately missed out on Watsu therapy with Ana Laura which I regret now that I have read more on it. (all the more reason to return!) To understand the beauty and magic of Anamaya, you have to experience it for yourself. It is a beautiful spot and a great place to recharge.'),
  (120, 'r556988088', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r556988088-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Our experience at Anamaya was absolutely wonderful!', 5, 'January 2018', 'Traveled as a couple', 'We just returned home from a wonderful week at Anamaya Resort in Costa Rica. It was our first time to Costa Rica. Overall, It was an amazing trip. All of the people we came across were very kind, warm and hospitable. As far as our experience at Anamaya it was absolutely wonderful! The property is situated on a bluff with the best view around! Not having been to Costa Rica before it was soooo nice to have the food provided and not have to worry about it. Having the massage services also available at the resort was icing on the cake. Laurent gave me two terrific deep tissue massages. I had asked for another deep tissue massage but she wasn''t available so they booked me with Barbara instead. The massage was okay but Barbara told me herself that wasn''t her style. My partner Michael had massages given by Diane and another young lady from Michigan(name escapes me) which he loved. The staff were absolutely wonderful! They were there to make sure every need was taken care of as well as they checked to see how each of our experiences were along the way. When we expressed dissatisfaction with anything they remedied it immediately. The shower head was full of sediment and they replace it right away. A couple of the massages we were overcharged but they also corrected that right away. Albert, Antonio, Manijay, Laura Gabriela and Maria are the absolute best thing Anamaya has going for it! They MADE the whole experience so pleasurable! Big hugs to them all! The food was amazing especially the Thai Fish Stew! OMG! I hear they are working on putting our a cookbook! Yum. The tour of the Anamaya farm was fascinating and the trip to Santa Teresa beach was fantastic! Laura Gabriela was so attentive and she made the beach experience fabulous! The chef gave a terrific tour of the farm too. He was extremely knowledgeable about every little thing. A There were a few things that were not ideal. They are as follows: there were six of us "on retreat" and then there were 16 there for Yoga Teacher Training(YTT). The groups were kept separate and we felt like we were the ugly step children sitting at the other table for meals. There were times when we wanted to swim in the pool and couldn''t because the YTT students were working in the yoga area adjacent to the house. We stayed in the Master Suite and we could hear the noise during the day from the common areas of the house. When we tried to nap for a couple hours we couldn''t because the YTT students were in the house laughing and carrying on. The volume at times was over the top. We communicated this to the staff twice. If we are to return to Anamaya it would be during an actual "yoga retreat" with a specific teacher putting it on or for an actual 3 week YTT as a student ONLY. The local teachers who we had for the yoga sessions were fine but all soooo very different which was not great. Perhaps in the future you might want to limit it to two yoga teachers on a week without a particular yoga retreat going on to keep it somewhat consistent. We didn''t feel like our yoga practice improved at all. I am a business professional myself and we all try new things to make more money. However, when it moves you away from the main intention it''s bad. I wouldn''t mix the YTT with other retreat people. If you are going to do YTT then just do that. If you going to do individual retreats then just do that. Having two different groups there at the same time with different intentions was awkward. Overall, Anamaya has going for it is nothing short of amazing! As I am finishing this review, I have decided we will return. Most likely for the Yoga Teacher Training.'),
  (121, 'r553270833', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r553270833-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Incredible resort and experience!', 5, 'December 2017', 'Traveled solo', 'Anamaya is an amazing place! Excellent service, beautiful and clean quarters, delicious healthy food, and thoughtful retreat programming. Ocean views and jungle feels, short hike from the Montezuma waterfall, zip lining and the beach. Feels secluded yet cozy.'),
  (122, 'r553042721', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r553042721-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Just Gets better and better', 5, 'December 2017', 'Traveled solo', 'This was my second time at Anamaya and my only concern in coming back was my first trip was perfect how could the second not be a let down??? The staff, the food, the grounds, everything absolutely perfect once again. Lola as a teacher was amazing, truly caring and made me better! Will 100% be back and couldn''t recommend this place more.'),
  (123, 'r552939088', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r552939088-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Life-changing experience', 5, 'December 2017', 'Traveled as a couple', 'Anamaya is my home away from home. Everything about the trip, from the room to the staff to the yoga teacher, to the AMAZING food, to the pool, to the treatments was absolutely mind blowing and worth every penny. I cannot wait until I return to this very special place!'),
  (124, 'r551583584', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r551583584-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Walked by paradise', 5, 'December 2017', 'Traveled with family', 'We did not book anything here but got lost in the forest surrounding the place. So we shouted at some small gate at the back and the owner came. He showed us his place and was very friendly. It was all very clean and relaxing.'),
  (125, 'r545504875', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r545504875-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Going to Anamaya was the best decision in my life so far', 5, 'June 2017', 'Traveled solo', 'This the most amazing resort I have visited. The energy and beauty of this place goes far beyond anything you can imagine from looking at their pictures. The staff make you a part of their family and you could not ask for anything more from them. The first day, trying the food, I was smiling for a solid hour after eating. The freshness and taste to the food was indescribably good. (Jeff if you would be willing to hook me up with recipes I would love it ;) ) As for the yoga teacher training, I never imagined I would go through such a positive transnational program and feel such a great change in myself. Thank you Jackie for the amazing program..... But a huge thank you who had everything organised so perfectly that I could just focus on my own journey and enjoy every minute of it!! My words are actually failing to describe Anamaya in it''s glorious entirety, so all if I can say is if you get a sniff of an opportunity to visit..... Grab it with both hands.'),
  (126, 'r543458293', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r543458293-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Mind blowing, beautiful environment, and best food ever', 5, 'September 2017', 'Traveled with friends', 'Phrases like, "Mind blowing, beautiful environment, and best food ever," can''t even begin to describe my transformational experience at Anamya. From the moment I started planning for my trip I felt supported and cared for. The staff was willing to go out of their way to make sure they took care of all my needs so that I could relax and enjoy everything Costa Rica had to offer. I had the opportunity to experience yoga, spa treatments, excursions to the beach, and make life long friends. I left having learned so much about the language, the culture, and how to cook fresh food. I would highly recommend this trip to anyone who is looking for adventure, escape and pure joy. Review for Watzu: Watuzu is a once in a life time experience of rebirth. Ana Laura takes you to her favorite tide pool where she creates the conditions for you to discover areas of your body that have have been tight from anxiety or stress. Then she uses the peaceful ocean to wash away old thoughts so you can explore new possibilities. I felt supported and free for the first time in many years and was able to remember what it was like to play, laugh, and let go. If you take life too seriously, I invite you to explore a different way of being with Ana Laura''s light and love. Review for Ashleigh: Ashleigh has the ability to create an environment that is warm, welcoming, and inspiring. She is knowledgeable in Strala yoga practices, meditation and essential oils. Before Anamaya, I was use to Baptiste Power Yoga so experiencing Strala yoga opened my eyes to a different way to practice when I need loosen up my body and go with the flow. I also had very little experience with meditation and now I have several different styles to apply when I need to become aware of the thoughts bouncing around in my head. I find using the affirmations and essential oils has helped me reconnect to the peace and joy I experienced while I was at Anamya. I learned so much from her and am grateful to continue to learn from her on social media.'),
  (127, 'r542677538', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r542677538-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Best Hoilday Ever!!', 5, 'October 2017', 'Traveled with friends', 'Anamaya is nothing short of magical! I had the pleasure of staying in the beautiful Bali Cabina...Wow!! Amazing! The staff at Anamaya are hands down the most welcoming and accommodating that I have ever experienced...by the time that you are ready to leave, they have become family. And the food...spectacular. As for the yoga retreat, an absolutely amazing teacher in Angela Plaquin. She made the entire time fun, informative and challenging! Make sure that you visit one of the many great spa services available and if possible, please try the Watsu Healing Therapy with AnaLaura...a wonderful experience like no other. I will definitely be returning to Anamaya to relax and refocus, but also to revisit the wonderful friends that I have made there. Thank you to all at Anamaya!!'),
  (128, 'r541183379', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r541183379-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Simply, Amazing.', 5, 'October 2017', 'Traveled solo', 'This place is really magical. Everything about it was perfect, from the room to the food. All of the staff is phenomenal and so welcoming. The view is endless and gets better and better the more you look at it. The pictures do it no justice. I would absolutely recommend it to anyone I meet and will hold Anamaya in a very special place in my heart.'),
  (129, 'r539989486', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r539989486-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing Stay', 5, 'October 2017', 'Traveled on business', 'I had the master suite, just above the main house. This was a convenient location, and had a beautiful view. The staff were super nice and helpful. The food was sooo good and healthy. We were trying to convince the staff to put out a recipe book :)'),
  (130, 'r539677522', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r539677522-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Magical', 5, 'October 2017', 'Traveled solo', 'This was my second trip to Anamaya. First time in 2013 left me rested, rejuvenated, re-focused. I am so grateful to have returned as the guest instructor last week. Anamaya offers the perfect balance between movement and rest, indulgence and health, introspection and interaction. A random gathering of people from around the globe with similar intent means fast friendships and a depth of connection and conversation unique tho the intimate setting of this amazing retreat. The staff are extra-ordinary, knowing each name upon arrival and full of warm smiles and the best hugs. While the staff is relaxed in the requisite short and t-shirts sutied to the weather and mood, the service is beyond 5 star. Grettel, Antonia, Albert, Laura, Manijay, and Ana Laura took care of our every need. They book shuttles, taxis, anticipate our needs before we know we have them. They treat you like family, and indeed a family you become. The food from Rancho Delicioso, with the creative mind of chef Jeff is exemplary and can be compared to any high end restaurant anywhere. The rooms are unique, simple, comfortable, each one offering a different look and experience. The housekeeping staff are amazing, leaving each room immaculate. The staff in the spa are masterful, offering highly skilled and diverse services. For a most unique and transformative, nurturing experience, you must have a WATSU massage with Ana Laura...it will touch you to your core! At Anamaya, the body and mind are nurtured in a way we rarely experience in our day to day lives. It is extra ordinary to see people truly relax. This place, with it''s the stunning physical beauty, is where you need must go. As a gift to yourself....Anamaya...it''s magic!'),
  (131, 'r534386948', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r534386948-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Transformative. The stuff of dreams.', 5, 'September 2017', 'Traveled with friends', 'I still dream about my time at Anamaya. When I first started looking at places for my first ever yoga retreat, I was unsure about the travel needed to get to Anamaya, nor was I sure about going to Costa Rica in the middle of rainy season, but I cannot gush about my experience at Anamaya enough. Everything for the week was beyond my expectations. The staff at Anamaya was like a family and they cared for us like we were family. When I encountered a last minute flight cancellation at the end of my trip, Laura said, "I will stay with you until we get this settled" and she found a solution to get me to the airport to make my flight home. Every day we were greeted with love, warmth and genuine care by every single person at Anamaya. The view, the food, the spa services, the experiences, the extras - like the fun circus performance, dancing, cooking and Spanish lessons, the accommodations, the other guests (who became like a family to us while we were there) - simply amazing. I honestly have no appetite since returning because I was so incredibly spoiled while we were there - such nourishing, healthy, stunning food. I connected to nature in a different way than I ever have in my life. I fell in love with the sound of rain on the yoga deck roof, having the sunrise wake me up in the morning, taking my evening shower outside, strolling on the beach, sweating from the breathless climb up the Montezuma mountain to get to the resort at the top of the hill, and just being outside in such a lush and lovely environment. It truly was a feast of the senses. The week was so much more than about the yoga. I meditated, played in the ocean, strolled on beaches, read, snorkeled, zip lined, swam, danced, laughed, ate some of the most amazing food ever, visited the farm where most of our food was grown, visited the town, hiked to the waterfall and received three excellent spa services (which were all incredible). We had a very small group the week I was there, but all of us connected like family sharing our meals at the same table and telling stories about our days and our lives outside of Anamaya. I honestly came home a better person. All the fears I had about traveling there (which was part of the adventure) or even visiting during the off season, were completely irrelevant in comparison to the amazing, transformative time I had while I was there. I''m already dreaming of going back. If you keep going back to Anamaya''s website and staring at the pictures and thinking about it, just go. You won''t regret it.'),
  (132, 'r528828792', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r528828792-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Just absolutely fantastic!', 5, 'September 2017', 'Traveled solo', 'From the staff, to the managers at the hotel, the yoga, the amenities and to the hotel rooms, and the FOOD. The stunning views, Anamaya is truly in my view a gem! The experience was just priceless. The infinity pool looking over the ocean, the dance performances by the resort on Thursday, omg! Just fantastic! I am definitely coming back! You made me more healthy, mentally, emotionally and physically. Miss all the staff there! I know why they call Nicoya a blue zone! If I lived there I would definitely live longer. Highly highly recommended!!!! When i got there we also saw the the turtle release! Amazing experience! Playa Hermosa was also amazing! Just everything was amazing! And the people that came with me were also just simply so friendly, relaxed and super nice - I give the resort credit for that because they create such a positive environment. Amazing!'),
  (133, 'r501956180', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r501956180-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'So much more than a resort - magical summer camp for adults', 5, 'July 2017', 'Traveled solo', 'I''m one week back from Anamaya and I''m pretty sure the experience has changed me forever. Yes, it has the best of everything when it comes to Costa Rican resorts. There''s a saltwater infinity pool. The yoga decks have spectacular sunrise and sunset views. It''s immaculately well-kept. The food is fresh, creative and delicious - healthy and whole, but you can still indulge in a good cup of coffee or glass of wine. The activities are top-rate from the ziplining to the surfing instruction. Wildlife -from monkeys to butterflies and hummingbirds - abounds. But Anamaya is also an experience and a way of life. I came as part of a week-long yoga retreat and not only were our yoga/meditation instructors great (and really set the vibe), but my fellow attendees were also just lovely, fascinating people. Relationships grow quickly at Anamaya because you share meals and activities (and a lot of interesting conversation!). I think a little more than half of us were traveling solo - but it didn''t really matter, as you get to know everyone by the end of the week. I initially hesitated on doing dorm-style housing as a late-30-something, but I adored my roommates. And what really makes Anamaya is the staff. I literally did not have to think of anything during my stay other than saying yes or no to activities and spa treatments. I have an allergy, so they made me special food. They learned all of our names. And the women who provided my spa treatments were just delightful to be around. Some tips: - Definitely recommend: zip-lining, surfing, watsu, reiki, horseback riding - As a bit of an introvert, I also took a day or two by myself at the beach and that was totally cool. No pressure to stick with a "program." - Their yoga mats, towels and props are top-notch - nice and grippy, even during a sweaty class. - Wake up early to soak up the sunrise/AM quiet time - magical - If you can swing it, take the Sansa or Nature Air flight in or out of Tambor - amazing views Bottom line: If you are tired, burnt out or just needing to shake things up, get yourself to Anamaya ASAP!'),
  (134, 'r497794287', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r497794287-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'The people here turn into family, Amazing yoga experience, peaceful place, relaxing and fun!', 5, 'March 2017', 'Traveled solo', 'This place is incredible, as soon as you walk on their property you feel welcomed and more relaxed. The views from the back are spectacular and pretty much every single room has a different view of the beautiful grounds and view that this yoga retreat is set on. So many different things you can do here as well. Of course there is yoga, but if you want excitement, there are waterfalls, hikes, boat trips with snorkeling and surfing on the beautiful beaches. The prices are great compared to most resorts that over price any "extras". Each meal here was incredible, but you could also easily walk down into town and eat something local on the beach. I''ve never been to a more accommodating resort.Their are no restrictions and curfews and things not to do. If you want to try something new they do their best to helping you do it. I have recommended everyone i know to this resort, even the people who do not do yoga, because just going for the spa services is incredible! I had the privilege of doing Watsu with Ana and Reiki which for me was not a new experience but a very powerful one after already being in such a spiritual and happy place. I cant wait to go back here to this magical place to visit my new family!'),
  (135, 'r491790808', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r491790808-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'It''s one of those places where you wish you could quit your job and just move there...', 5, 'May 2017', 'Traveled solo', 'It''s been a week since I''m back home and I''m still in full withdrawal mode... I CAN''T wait to go back again! It''s not just the amazing views from the infinity pool where you can swim at any time of day or night, or the out-of-this-world food where you''ll feel like a kid anxiously looking forward to the next meal, or the massages that will make you fall asleep and then you''ll want to take a nap after, or the yoga classes that will challenge you and rejuvenate you at the same time, or the iguanas jumping from the roof to devour a seemingly innocent crab, or the voluntary desire to wake up at 5:00 am just to see the amazing sunrise over the mountains and the ocean, or the howler monkeys responding back to the group after singing OM a few times, or the beach bonfire while watching the sunset and listening to a local singing with his ukulele, or the 426 steps you have to take back up after hiking to the most beautiful waterfall... it''s not just all that, but the AMAZING people you meet, the new friendships made, where you know that no matter what your story is you''ll fit right in... like-minded spirits. Stop thinking about it and just go... you won''t regret it.'),
  (136, 'r490788002', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r490788002-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'LOOK NO FURTHER--YOU''VE FOUND THE PERFECT PLACE!!', 5, 'June 2017', 'Traveled with friends', 'Where do I even start? If I could rate this place any better, I would. I spent weeks of looking at reviews, checking prices, dates, etc for a yoga retreat. Finally took the leap and booked Anamaya. I can not describe how perfect this place is, the staff, the food, the location, the views....everything is outstanding. I left the retreat feeling completely rejuvenated & more than satisfied. TAKE THE LEAP AND BOOK ANAMAYA!!'),
  (137, 'r484417044', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r484417044-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Paradise found!', 5, 'April 2017', 'Traveled with friends', 'This retreat is fantastic! The food is outstanding and plant based! The yoga is fabulous as is the areas you do your yoga classes in. The grounds and accommodations are tropical and very blended with the natural flora and fauna. The staff are so helpful making your stay relaxing and they set up all activities and transportation outside of the the retreat. The spa has so many choices you could stay 2 weeks and do 2 treatments a day and not try everything. I cant wait to go back!'),
  (138, 'r483635132', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r483635132-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Great Food, Yoga, Surf = Awesome', 5, 'April 2017', 'Traveled with family', 'Father/Daughter trip to Anamaya was more than we could have dreamed. The amazing food. perfectly presented, twice daily yoga with Kat and trips to great surf breaks and other adventures in between left us feeling great. The staff is very helpful about getting your details in order both with travel and once you are there. They figured your final payment at the end, which ended up being a cheaper price for us with the surf plan we did.'),
  (139, 'r480514672', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r480514672-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'The Garden of Eden!', 5, 'March 2017', 'Traveled solo', 'Stop searching for any other places to visit in Costa Rica and book your trip to Anamaya NOW! I promise you will not regret this trip of a lifetime. The resort is situated overlooking the pristine jungle and ocean...I heard the waves crashing against the shore all week long from my room and the main dining area. All the details are lovely, clean rooms, safe surroundings, Delicious Food, and plenty of fun activities including Yoga. The staff is AMAZING!!! So warm and caring...they handle every detail to ensure you have the best experience. I loved the pool and the yoga deck where we greeted the sunrise each morning during our practice. Truly breathtaking views! The flowers and nature are also lovely! I saw a train of monkeys and tons of beautiful birds. I cannot wait to book my next trip to Anamaya!! Peace Light Love :)'),
  (140, 'r476460505', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r476460505-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Paradise!', 5, 'March 2017', 'Traveled as a couple', 'I had high expectations of Anamaya and they were exceeded a million times over! The staff are the absolute best ever! They are kind, talented, and detail-oriented. You leave feeling like they are your family. The resort is utterly breathtaking and the food is amazing! I would live at Anamaya if I could and Anamaya will always have a piece of my heart! Do the Watsu with Ana- it is life changing!'),
  (141, 'r441198962', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r441198962-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Amazing time. Just go', 5, 'December 2015', 'Traveled with friends', 'I had such a healthy fun experience. Location is beautiful!. Yoga on deck above the ocean. Food was delicious and healthy. Lots to do or just hang out. People are amazing there. Would def recommend and pretty reasonably priced for what you get.'),
  (142, 'r440962120', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r440962120-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Fabulous from start to finish', 5, 'November 2016', 'Traveled solo', 'Where to start, this is a wonderful , friendly retreat offering first class facilities .... the accommodation is lovely , the yoga and the studios very special , excellent add on therapies - Reiki and Watsu were amazing! The friendly service through out made it a very special week. The food was out of this world..........'),
  (143, 'r437140731', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r437140731-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Beautiful place and people!', 5, 'November 2016', 'Traveled with family', 'I attended a one week yoga retreat at Anamaya. The location (especially the stellar view from the yoga deck) cannot be beat. The infinity pool was awesome. The staff was so wonderful and helpful with anything I needed. You don''t have to plan anything in advance. Just show up and they will help you book surfing, excursions, etc if you want to do that in addition to yoga. We had awesome people on our retreat from all over the world and all walks of life. It was like summer camp for grown ups in the best possible way. The food was delicious and healthy. My cousin is a vegan and I eat everything and we both were satisfied (they go out of their way to accommodate different diets and allergies). I honestly don''t have a single bad thing to say and I hope to go back one day. It was so much more than a vacation.'),
  (144, 'r426225377', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r426225377-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Exactly the escape I needed', 5, 'August 2016', 'Traveled solo', 'This was my first time traveling alone outside the country, as a birthday present to myself. I loved Anamaya and will definitely be back. I was looking for a place to escape the world for a week, and unwind with yoga, massages, and surfing. I stayed in the Prana Cabina, which was perfect for a solo traveler looking for alone time. Throughout the week, I got to know the other retreaters and create new friendships. I loved that you could do as little or as much as you want, be as social or "alone time" as you needed, and customize your week to be what you''d like it to be. I did meditation most mornings, yoga every morning, and surfing 2x during the week, then plenty of pool and hammock time for reading and relaxing. Definitely do the Watsu water massage, especially if you''re there in need of healing. Loved touring the organic farm. The food was INCREDIBLE. I cannot wait until the cookbook comes up. The staff was so welcoming and attentive. It was a big decision for me to take a week for myself, but so worth it. It was the time and healing I needed. Thank you, Anamaya!!'),
  (145, 'r415799919', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r415799919-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Most Amazing, Life Changing, and Fulfilling Experience EVER.', 5, 'July 2016', 'Traveled solo', 'I spent months deciding if I was brave enough to do my first solo female trip somewhere. The moment I found Anamaya in all the online reviews, I knew that if I was ever to travel alone anywhere for my first time, it would be to Anamaya. From the moment I contacted Anamaya, they were quick to respond to all of my questions, and reassured me about all my nervousness and concerns. From the moment I landed at San Jose airport, and met some of the friendly women who would be joining me in Anamaya, I knew finally that I would not be alone! One crazy propeller plane ride, and many dirt roads later... we arrived in Montezuma. From the moment I stepped foot onto Anamaya''s property, I felt the magic in and around my soul. I felt like home immediately. Every there with you is a like-minded individual, most likely looking for the same things in their life at that moment. A life changing mind-body-soul experience. The property is unlike anything I have ever experienced. It is like one big home, with many small guest houses littered around the jungle property. From almost anywhere you have a sweeping ocean view. Everything is beautiful, and the decor is very Moroccan and comforting. The staff is immediately like family to you, and they take care of you like family. The food is out of this world. Everything is so healthy and delicious. My stomach had never been happier than it was that one week. The yoga is by far the best yoga I have ever done. I know this is all dependent on the instructors, but I have a feeling anyone Anamaya would pick will be amazing. Their yoga decks are out of this world beautiful. You feel like you are in a dream, practicing yoga, with the sounds of the jungle, thunder, rain, butterflies flying around you. So tantric and mystifying. The activities are ALL so fun. Do as many as you can, but make sure to leave enough time to relax and be alone. Coming alone on this trip, I am surprised how little I spent by myself. I literally had to carve out time in my days to sit and meditate myself, otherwise you are with friends, having a blast! I could honestly go on, and on, and on about this place. But all you need to know, is that you need to go here, SOON. You WON''T regret it, and it WILL change your life.'),
  (146, 'r415064090', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r415064090-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Just Amazing!!', 5, 'August 2016', 'Traveled solo', 'I really enjoyed my time at Anamaya. I attended a one-week yoga retreat, and didn''t know exactly what to expect. And I was a little nervous about sharing living quarters, but it was honestly a great part of the entire experience. The rooms are beautiful and spotless. This place is truly amazing! While the property is absolutely beautiful, but the best part is the staff -- they make everything so easy. They arrange everything (from excursions to airport transfers) so you can truly relax and enjoy your time. The food was also amazing and totally inspired me to eat more of a plant-based diet. I really did not want to leave. If you are considering a retreat at Anamaya - do yourself a favor and go!!'),
  (147, 'r405269468', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r405269468-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Most Relaxing and Self-Fulfilling Vacation Ever!!', 5, 'July 2016', 'Traveled solo', 'This location, staff, and schedule of activities is everything you could ever ask for in a surf and yoga camp. I traveled alone and made so many friends with amazing women that just enhanced my self exploration and learning. I can''t recommend it enough - go for yourself and take a break to see what life is really about!'),
  (148, 'r396930946', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r396930946-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Life changing!', 5, 'July 2016', 'Traveled solo', 'My mom and I booked this trip for my college graduation gift and it was more than I ever expected. We did the week yoga retreat with the adventure package. I have nothing but amazing things to say about Anamaya, the staff, and the experience. Everyone makes you feel right at home. The food and views are unreal!! I already want to go back and I''ve been home for a week. I highly suggest coming here. Thank you Anamaya. Pura Vida!'),
  (149, 'r393916484', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r393916484-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Best trip ever!', 5, 'July 2016', 'Traveled solo', 'I can not say enough about this wonderful place. I was traveling by myself and picked this resort based on other trip advisor reviews, and I was not disappointed. All the rooms are unique (I stayed in the Ganesh cabin, which was amazing,) and the staff becomes like family. The food is amazing and the yoga decks have the most perfect views. The property is even more beautiful in person than the photos can show. The staff was also great about quickly returning my emails before my trip and answering all my questions, which made me feel better about heading there alone. I thought it was a great value, and I can''t wait to go back. Book your room as soon as you can!'),
  (150, 'r390272117', 'https://www.tripadvisor.com/ShowUserReviews-g309278-d1593953-r390272117-Anamaya_Resort_Retreat_Center-Montezuma_Province_of_Puntarenas.html', 'Simply amazing! A truly special place.', 5, 'June 2016', 'Traveled solo', 'The staff, the location, the food, the accommodations - everything about this place is incredible. This is my second time here - I visited first for a one week yoga retreat, and came back for a four week teacher training. The experience was consistently incredible. I''ve stayed in both the Gaia House and Garuda''s Nest (the treehouse). The cleaning staff are so friendly and do a really thorough job cleaning the rooms and making sure you have towels and everything you need. The views from the unique accommodations on the property are breathtaking. Chef Jeff and his team create delicious gluten free meals and are very accommodating to any other dietary needs. You can tell a lot of love goes into the cooking as it''s so tasty and beautifully presented. Preparing and serving 3 meals a day and keeping it interesting and consistently high quality must be a challenge but the team delivered for every meal! I want to cook all of the recipes at home! The two yoga decks, the main house, and the pool are all gorgeous and offer beautiful views of the hills, jungle, and the ocean. Any pictures you see online just don''t do it justice. The team at Anamaya are some of the sweetest, most wonderful people. So helpful, friendly, and accommodating. I gained new friends in the people who work here :) You feel truly at home and welcome in this magical place, I rave about this to everyone and can''t wait for a chance to go back again. If you''re considering staying here for a retreat or training, stop thinking about it and just do it - you won''t be disappointed.');

-- Sanity check.
do $$
declare cnt int;
begin
  select count(*) into cnt from public.testimonials;
  raise notice 'testimonials row count after import: %', cnt;
end $$;
